
/* ===== heys_dev_utils.js ===== */
// 🆕 PERF v9.2: Метка момента когда boot-core начал исполняться
window.__heysPerfMark && window.__heysPerfMark('boot-core: execute start');

/**
 * HEYS Development Utils v1.1
 * =============================
 * Утилиты для условного логирования в development/production режимах
 * 
 * 🔇 v4.7.0: По умолчанию логи ОТКЛЮЧЕНЫ даже на localhost
 *            Для включения: DEV.enable() или ?debug=verbose в URL
 */

(function () {
  'use strict';

  const logControl = window.__heysLogControl || window.HEYS?.logSettings || null;

  // 🔇 v4.7.0: Логи отключены по умолчанию для чистоты консоли
  // Включить можно через:
  // 1. URL параметр: ?debug=verbose
  // 2. В консоли: DEV.enable()
  // 3. localStorage: localStorage.setItem('heys_debug_verbose', 'true')
  const forceVerbose = location.search.includes('debug=verbose') ||
    localStorage.getItem('heys_debug_verbose') === 'true' ||
    logControl?.isEnabled?.('all') === true;

  let isVerbose = forceVerbose;

  // Экспортируем в window.DEV
  window.DEV = {
    /**
     * Логирование только при включённом verbose режиме
     * @param {...any} args - Аргументы для console.log
     */
    log: function (...args) {
      if (isVerbose) {
        console.log(...args);
      }
    },

    /**
     * Предупреждения только при включённом verbose режиме
     * @param {...any} args - Аргументы для console.warn
     */
    warn: function (...args) {
      if (isVerbose) {
        console.warn(...args);
      }
    },

    /**
     * Информационные сообщения только при включённом verbose режиме
     * @param {...any} args - Аргументы для console.info
     */
    info: function (...args) {
      if (isVerbose) {
        console.info(...args);
      }
    },

    /**
     * Debug сообщения только при включённом verbose режиме
     * @param {...any} args - Аргументы для console.debug
     */
    debug: function (...args) {
      if (isVerbose) {
        console.debug(...args);
      }
    },

    /**
     * Включить verbose логирование
     */
    enable: function () {
      isVerbose = true;
      localStorage.setItem('heys_debug_verbose', 'true');
      logControl?.all?.();
      console.log('🔊 DEV logging ENABLED. Reload to see all logs.');
    },

    /**
     * Выключить verbose логирование
     */
    disable: function () {
      isVerbose = false;
      localStorage.removeItem('heys_debug_verbose');
      logControl?.reset?.();
      console.log('🔇 DEV logging DISABLED.');
    },

    /**
     * Проверка режима verbose
     * @returns {boolean} true если verbose режим
     */
    isVerbose: function () {
      return isVerbose;
    },

    logs: {
      groups: function () {
        return logControl?.getKnownGroups?.() || [];
      },
      enabled: function () {
        return logControl?.getEnabledGroups?.() || [];
      },
      enable: function () {
        return logControl?.enable?.apply(logControl, arguments);
      },
      disable: function () {
        return logControl?.disable?.apply(logControl, arguments);
      },
      only: function () {
        return logControl?.only?.apply(logControl, arguments);
      },
      reset: function () {
        return logControl?.reset?.();
      },
      all: function () {
        return logControl?.all?.();
      }
    }
  };

  // Алиас для краткости
  window.devLog = window.DEV.log;
  window.devWarn = window.DEV.warn;
})();


/* ===== heys_feature_flags_v1.js ===== */
/**
 * HEYS Feature Flags v1.0
 * =======================
 * Система управления feature flags для безопасного постепенного внедрения модулей
 * 
 * Паттерн использования:
 *   HEYS.featureFlags.isEnabled('newModularApp') // boolean
 *   HEYS.featureFlags.enable('newModularApp')
 *   HEYS.featureFlags.disable('newModularApp')
 * 
 * Научная основа: Feature Toggles (Martin Fowler 2017)
 */

(function () {
  'use strict';

  const HEYS = window.HEYS = window.HEYS || {};
  const devLog = (...args) => window.DEV?.log?.(...args);
  const devWarn = (...args) => window.DEV?.warn?.(...args);

  // Storage key для флагов
  const FLAGS_KEY = 'heys_feature_flags';

  // Значения по умолчанию для всех флагов
  const DEFAULT_FLAGS = {
    // === App Refactoring Flags ===
    'modular_platform_apis': false,     // Новый модуль Platform APIs
    'modular_pwa': false,               // Новый модуль PWA
    'modular_auth': false,              // Новый модуль Auth Integration
    'modular_navigation': false,        // Новый модуль Navigation
    'modular_sync': false,              // Новый модуль Sync State Machine
    'modular_bootstrap': false,         // Новый модуль Bootstrap (инициализация)

    // === Режим разработки ===
    'dev_module_logging': false,        // Детальное логирование загрузки модулей
    'dev_performance_tracking': false,  // Трекинг производительности модулей

    // === Rollback флаг ===
    'use_legacy_monolith': false,       // true = старый код, false = новые модули
  };

  /**
   * Загрузить флаги из localStorage
   * @returns {Object} Объект с флагами
   */
  function loadFlags() {
    try {
      const stored = localStorage.getItem(FLAGS_KEY);
      if (!stored) return { ...DEFAULT_FLAGS };

      const parsed = JSON.parse(stored);
      // Мержим с дефолтами на случай новых флагов
      return { ...DEFAULT_FLAGS, ...parsed };
    } catch (e) {
      devWarn('[FeatureFlags] Failed to load flags:', e);
      return { ...DEFAULT_FLAGS };
    }
  }

  /**
   * Сохранить флаги в localStorage
   * @param {Object} flags - Объект с флагами
   */
  function saveFlags(flags) {
    try {
      localStorage.setItem(FLAGS_KEY, JSON.stringify(flags));
    } catch (e) {
      devWarn('[FeatureFlags] Failed to save flags:', e);
    }
  }

  // Текущее состояние флагов
  let currentFlags = loadFlags();

  /**
   * Feature Flags API
   */
  HEYS.featureFlags = {
    /**
     * Проверить, включен ли флаг
     * @param {string} flagName - Имя флага
     * @returns {boolean} true если флаг включен
     */
    isEnabled(flagName) {
      return currentFlags[flagName] === true;
    },

    /**
     * Включить флаг
     * @param {string} flagName - Имя флага
     */
    enable(flagName) {
      if (!(flagName in DEFAULT_FLAGS)) {
        devWarn(`[FeatureFlags] Unknown flag: ${flagName}`);
        return;
      }
      currentFlags[flagName] = true;
      saveFlags(currentFlags);
      devLog(`[FeatureFlags] Enabled: ${flagName}`);
    },

    /**
     * Выключить флаг
     * @param {string} flagName - Имя флага
     */
    disable(flagName) {
      if (!(flagName in DEFAULT_FLAGS)) {
        devWarn(`[FeatureFlags] Unknown flag: ${flagName}`);
        return;
      }
      currentFlags[flagName] = false;
      saveFlags(currentFlags);
      devLog(`[FeatureFlags] Disabled: ${flagName}`);
    },

    /**
     * Получить все флаги (для отладки)
     * @returns {Object} Объект с состоянием всех флагов
     */
    getAll() {
      return { ...currentFlags };
    },

    /**
     * Сбросить все флаги к дефолтам
     */
    reset() {
      currentFlags = { ...DEFAULT_FLAGS };
      saveFlags(currentFlags);
      devLog('[FeatureFlags] Reset to defaults');
    },

    /**
     * Включить все модульные флаги (для тестирования полного перехода)
     */
    enableAllModules() {
      currentFlags.modular_platform_apis = true;
      currentFlags.modular_pwa = true;
      currentFlags.modular_auth = true;
      currentFlags.modular_navigation = true;
      currentFlags.modular_sync = true;
      currentFlags.modular_bootstrap = true;
      currentFlags.use_legacy_monolith = false;
      saveFlags(currentFlags);
      devLog('[FeatureFlags] Enabled all modules');
    },

    /**
     * Вернуться к legacy монолиту (откат)
     */
    rollbackToLegacy() {
      currentFlags.modular_platform_apis = false;
      currentFlags.modular_pwa = false;
      currentFlags.modular_auth = false;
      currentFlags.modular_navigation = false;
      currentFlags.modular_sync = false;
      currentFlags.modular_bootstrap = false;
      currentFlags.use_legacy_monolith = true;
      saveFlags(currentFlags);
      devLog('[FeatureFlags] Rolled back to legacy monolith');
    },

    /**
     * Постепенное включение модулей (фазированный rollout)
     * @param {number} phase - Номер фазы (1-6)
     */
    enablePhase(phase) {
      // Фаза 1: Platform APIs
      if (phase >= 1) {
        currentFlags.modular_platform_apis = true;
      }
      // Фаза 2: PWA
      if (phase >= 2) {
        currentFlags.modular_pwa = true;
      }
      // Фаза 3: Bootstrap (инициализация)
      if (phase >= 3) {
        currentFlags.modular_bootstrap = true;
      }
      // Фаза 4: Auth
      if (phase >= 4) {
        currentFlags.modular_auth = true;
      }
      // Фаза 5: Navigation
      if (phase >= 5) {
        currentFlags.modular_navigation = true;
      }
      // Фаза 6: Sync + отключение legacy
      if (phase >= 6) {
        currentFlags.modular_sync = true;
        currentFlags.use_legacy_monolith = false;
      }

      saveFlags(currentFlags);
      devLog(`[FeatureFlags] Enabled phase ${phase}`);
    }
  };

  // Алиас для краткости
  HEYS.flags = HEYS.featureFlags;

  // Логирование инициализации (только в dev режиме)
  if (window.DEV?.isDev?.()) {
    devLog('[FeatureFlags] Initialized with flags:', currentFlags);
  }
})();


/* ===== heys_module_perf_v1.js ===== */
/**
 * HEYS Module Performance Tracker v1.0
 * =====================================
 * Система мониторинга производительности загрузки и работы модулей
 * 
 * Паттерн использования:
 *   HEYS.modulePerf.startLoad('module_name')
 *   HEYS.modulePerf.endLoad('module_name')
 *   HEYS.modulePerf.getReport() // получить отчёт
 * 
 * Научная основа: User-centric Performance Metrics (Google Web Vitals)
 */

(function () {
  'use strict';

  const HEYS = window.HEYS = window.HEYS || {};
  const devLog = (...args) => window.DEV?.log?.(...args);
  const devWarn = (...args) => window.DEV?.warn?.(...args);

  // Storage для метрик
  const PERF_KEY = 'heys_module_perf';
  const PERF_HISTORY_LIMIT = 10; // храним последние 10 загрузок

  // Текущие измерения (в памяти)
  const measurements = new Map();

  const readStoredValue = (key, fallback = null) => {
    let value;
    if (HEYS.store?.get) {
      value = HEYS.store.get(key, fallback);
    } else if (HEYS.utils?.lsGet) {
      value = HEYS.utils.lsGet(key, fallback);
    } else {
      try {
        value = localStorage.getItem(key);
      } catch (e) {
        return fallback;
      }
    }

    if (value == null) return fallback;

    if (typeof value === 'string') {
      if (value.startsWith('¤Z¤') && HEYS.store?.decompress) {
        try {
          value = HEYS.store.decompress(value.slice(3));
        } catch (e) { }
      }
      try {
        return JSON.parse(value);
      } catch (e) {
        return value;
      }
    }

    return value;
  };

  const writeStoredValue = (key, value) => {
    if (HEYS.store?.set) {
      return HEYS.store.set(key, value);
    }
    if (HEYS.utils?.lsSet) {
      return HEYS.utils.lsSet(key, value);
    }
    localStorage.setItem(key, JSON.stringify(value));
  };

  // История метрик (в localStorage)
  let perfHistory = loadHistory();

  /**
   * Загрузить историю из localStorage
   * @returns {Array} Массив с историей загрузок
   */
  function loadHistory() {
    try {
      return readStoredValue(PERF_KEY, []);
    } catch (e) {
      devWarn('[ModulePerf] Failed to load history:', e);
      return [];
    }
  }

  /**
   * Сохранить историю в localStorage
   */
  function saveHistory() {
    try {
      // Ограничиваем размер истории
      const limited = perfHistory.slice(-PERF_HISTORY_LIMIT);
      writeStoredValue(PERF_KEY, limited);
    } catch (e) {
      devWarn('[ModulePerf] Failed to save history:', e);
    }
  }

  /**
   * Module Performance API
   */
  HEYS.modulePerf = {
    /**
     * Начать измерение загрузки модуля
     * @param {string} moduleName - Имя модуля
     */
    startLoad(moduleName) {
      if (!performance || !performance.now) {
        devWarn('[ModulePerf] Performance API not available');
        return;
      }

      measurements.set(moduleName, {
        name: moduleName,
        startTime: performance.now(),
        startTimestamp: Date.now(),
        endTime: null,
        duration: null,
        success: null,
        error: null
      });

      if (HEYS.featureFlags?.isEnabled('dev_module_logging')) {
        devLog(`[ModulePerf] 📦 Loading: ${moduleName}`);
      }
    },

    /**
     * Завершить измерение загрузки модуля
     * @param {string} moduleName - Имя модуля
     * @param {boolean} success - Успешно ли загружен
     * @param {Error} error - Ошибка (если была)
     */
    endLoad(moduleName, success = true, error = null) {
      const measurement = measurements.get(moduleName);
      if (!measurement) {
        devWarn(`[ModulePerf] No start measurement for: ${moduleName}`);
        return;
      }

      const endTime = performance.now();
      measurement.endTime = endTime;
      measurement.duration = endTime - measurement.startTime;
      measurement.success = success;
      measurement.error = error ? error.message : null;

      // Добавляем в историю
      perfHistory.push({ ...measurement });
      saveHistory();

      // Логирование
      const emoji = success ? '✅' : '❌';
      const duration = measurement.duration.toFixed(2);

      if (HEYS.featureFlags?.isEnabled('dev_module_logging')) {
        devLog(`[ModulePerf] ${emoji} ${moduleName}: ${duration}ms`);
      }

      // Предупреждение о медленной загрузке (>500ms)
      if (success && measurement.duration > 500) {
        devWarn(`[ModulePerf] ⚠️ Slow load: ${moduleName} took ${duration}ms`);
      }

      // Удаляем из активных измерений
      measurements.delete(moduleName);
    },

    /**
     * Получить отчёт о производительности
     * @returns {Object} Объект с отчётом
     */
    getReport() {
      const history = [...perfHistory];

      // Группируем по модулям
      const byModule = {};
      history.forEach(m => {
        if (!byModule[m.name]) {
          byModule[m.name] = [];
        }
        byModule[m.name].push(m);
      });

      // Статистика по каждому модулю
      const stats = {};
      Object.keys(byModule).forEach(name => {
        const loads = byModule[name];
        const durations = loads.filter(l => l.success).map(l => l.duration);

        stats[name] = {
          totalLoads: loads.length,
          successfulLoads: loads.filter(l => l.success).length,
          failedLoads: loads.filter(l => !l.success).length,
          avgDuration: durations.length > 0
            ? (durations.reduce((a, b) => a + b, 0) / durations.length).toFixed(2)
            : null,
          minDuration: durations.length > 0 ? Math.min(...durations).toFixed(2) : null,
          maxDuration: durations.length > 0 ? Math.max(...durations).toFixed(2) : null,
          lastLoad: loads[loads.length - 1]
        };
      });

      return {
        totalModules: Object.keys(stats).length,
        stats,
        rawHistory: history
      };
    },

    /**
     * Получить читаемый отчёт в консоль
     */
    printReport() {
      const report = this.getReport();
      devLog('[ModulePerf] Performance Report', report);
    },

    /**
     * Очистить историю
     */
    clearHistory() {
      perfHistory = [];
      saveHistory();
      devLog('[ModulePerf] History cleared');
    },

    /**
     * Получить список активных измерений
     * @returns {Array} Массив с активными измерениями
     */
    getActiveMeasurements() {
      return Array.from(measurements.values());
    },

    /**
     * Экспорт метрик для анализа
     * @returns {string} JSON строка с метриками
     */
    export() {
      const report = this.getReport();
      const data = {
        timestamp: Date.now(),
        userAgent: navigator.userAgent,
        ...report
      };
      return JSON.stringify(data, null, 2);
    }
  };

  // Алиас для краткости
  HEYS.perf = HEYS.modulePerf;

  // Логирование инициализации
  if (window.DEV?.isDev?.()) {
    devLog('[ModulePerf] Initialized');
  }
})();


/* ===== heys_module_loader_v1.js ===== */
/**
 * HEYS Module Loader v1.0
 * =======================
 * Система загрузки модулей с поддержкой feature flags и rollback
 * 
 * Паттерн использования:
 *   await HEYS.moduleLoader.load('module_name', 'path/to/module.js')
 *   HEYS.moduleLoader.getStatus('module_name')
 *   await HEYS.moduleLoader.loadAll(moduleList)
 * 
 * Научная основа: Progressive Enhancement (Aaron Gustafson 2008)
 */

(function () {
  'use strict';

  const HEYS = window.HEYS = window.HEYS || {};
  const devLog = (...args) => window.DEV?.log?.(...args);
  const devWarn = (...args) => window.DEV?.warn?.(...args);
  const trackError = (err, context) => HEYS.analytics?.trackError?.(err, context);

  // Статус модулей
  const MODULE_STATUS = {
    PENDING: 'pending',
    LOADING: 'loading',
    LOADED: 'loaded',
    ERROR: 'error',
    SKIPPED: 'skipped'
  };

  // Реестр загруженных модулей
  const loadedModules = new Map();

  // Реестр манифестов зависимостей
  const manifests = new Map();

  const trackModuleError = (err, context) => {
    trackError(err, context);
  };

  /**
   * Module Loader API
   */
  HEYS.moduleLoader = {
    /**
     * Загрузить модуль
     * @param {string} moduleName - Имя модуля
     * @param {string} modulePath - Путь к модулю
     * @param {Object} options - Опции загрузки
     * @returns {Promise<boolean>} true если успешно загружен
     */
    async load(moduleName, modulePath, options = {}) {
      const {
        required = false,      // Обязательный модуль?
        retry = 2,            // Количество попыток при ошибке
        timeout = 10000,      // Таймаут загрузки (мс)
        flagName = null       // Feature flag для проверки
      } = options;

      // Проверяем feature flag если указан
      if (flagName && !HEYS.featureFlags?.isEnabled(flagName)) {
        loadedModules.set(moduleName, {
          name: moduleName,
          status: MODULE_STATUS.SKIPPED,
          reason: `Feature flag '${flagName}' is disabled`
        });

        if (HEYS.featureFlags?.isEnabled('dev_module_logging')) {
          devLog(`[ModuleLoader] ⏭️ Skipped: ${moduleName} (flag disabled)`);
        }

        return false;
      }

      // Модуль уже загружен?
      if (loadedModules.has(moduleName) &&
        loadedModules.get(moduleName).status === MODULE_STATUS.LOADED) {
        if (HEYS.featureFlags?.isEnabled('dev_module_logging')) {
          devLog(`[ModuleLoader] ♻️ Already loaded: ${moduleName}`);
        }
        return true;
      }

      // Начинаем загрузку
      loadedModules.set(moduleName, {
        name: moduleName,
        status: MODULE_STATUS.LOADING,
        startTime: Date.now()
      });

      // Трекинг производительности
      HEYS.modulePerf?.startLoad(moduleName);

      // Попытки загрузки с retry
      let lastError = null;
      for (let attempt = 1; attempt <= retry; attempt++) {
        try {
          // Загружаем скрипт
          await loadScript(modulePath, timeout);

          // Успешно загружен
          loadedModules.set(moduleName, {
            name: moduleName,
            status: MODULE_STATUS.LOADED,
            startTime: loadedModules.get(moduleName).startTime,
            endTime: Date.now(),
            duration: Date.now() - loadedModules.get(moduleName).startTime,
            path: modulePath
          });

          HEYS.modulePerf?.endLoad(moduleName, true);

          // 🆕 Heartbeat для watchdog — модуль загружен, app ещё жив
          if (typeof window !== 'undefined') {
            window.__heysLoadingHeartbeat = Date.now();
          }

          if (HEYS.featureFlags?.isEnabled('dev_module_logging')) {
            devLog(`[ModuleLoader] ✅ Loaded: ${moduleName}`);
          }

          return true;

        } catch (error) {
          lastError = error;

          if (attempt < retry) {
            // Ждём перед повторной попыткой (exponential backoff)
            const delay = Math.pow(2, attempt) * 100;
            await new Promise(resolve => setTimeout(resolve, delay));

            if (HEYS.featureFlags?.isEnabled('dev_module_logging')) {
              devLog(`[ModuleLoader] 🔄 Retry ${attempt}/${retry}: ${moduleName}`);
            }
          }
        }
      }

      // Все попытки неудачны
      loadedModules.set(moduleName, {
        name: moduleName,
        status: MODULE_STATUS.ERROR,
        error: lastError?.message || 'Unknown error',
        path: modulePath
      });

      HEYS.modulePerf?.endLoad(moduleName, false, lastError);

      const errorMsg = `Failed to load ${moduleName}: ${lastError?.message}`;

      if (required) {
        // Обязательный модуль — бросаем ошибку
        trackError(lastError || new Error(errorMsg), { source: 'heys_module_loader_v1.js', moduleName, required: true });
        devWarn(`[ModuleLoader] ❌ ${errorMsg}`);
        throw new Error(errorMsg);
      } else {
        // Необязательный модуль — предупреждение
        devWarn(`[ModuleLoader] ⚠️ ${errorMsg}`);
        return false;
      }
    },

    /**
     * Загрузить несколько модулей параллельно
     * @param {Array} modules - Массив модулей [{name, path, options}]
     * @returns {Promise<Object>} Объект с результатами
     */
    async loadAll(modules) {
      const results = await Promise.allSettled(
        modules.map(m => this.load(m.name, m.path, m.options || {}))
      );

      const summary = {
        total: modules.length,
        loaded: 0,
        failed: 0,
        skipped: 0
      };

      results.forEach((result, index) => {
        const module = modules[index];
        const status = loadedModules.get(module.name)?.status;

        if (status === MODULE_STATUS.LOADED) summary.loaded++;
        else if (status === MODULE_STATUS.ERROR) summary.failed++;
        else if (status === MODULE_STATUS.SKIPPED) summary.skipped++;
      });

      if (HEYS.featureFlags?.isEnabled('dev_module_logging')) {
        devLog('[ModuleLoader] Batch load complete:', summary);
      }

      return summary;
    },

    /**
     * Получить статус модуля
     * @param {string} moduleName - Имя модуля
     * @returns {Object|null} Объект со статусом или null
     */
    getStatus(moduleName) {
      return loadedModules.get(moduleName) || null;
    },

    /**
     * Получить все загруженные модули
     * @returns {Array} Массив с модулями
     */
    getAllModules() {
      return Array.from(loadedModules.values());
    },

    /**
     * Проверить, загружен ли модуль
     * @param {string} moduleName - Имя модуля
     * @returns {boolean} true если модуль загружен
     */
    isLoaded(moduleName) {
      const status = loadedModules.get(moduleName)?.status;
      return status === MODULE_STATUS.LOADED;
    },

    /**
     * Получить отчёт о загрузке
     */
    getReport() {
      const modules = this.getAllModules();

      return {
        total: modules.length,
        loaded: modules.filter(m => m.status === MODULE_STATUS.LOADED).length,
        failed: modules.filter(m => m.status === MODULE_STATUS.ERROR).length,
        skipped: modules.filter(m => m.status === MODULE_STATUS.SKIPPED).length,
        modules
      };
    },

    /**
     * Вывести отчёт в консоль
     */
    printReport() {
      const report = this.getReport();

      devLog('[ModuleLoader] Load Report', {
        total: report.total,
        loaded: report.loaded,
        failed: report.failed,
        skipped: report.skipped,
        modules: report.modules
      });
    }
    ,
    /**
     * Зарегистрировать манифест зависимостей
     * @param {string} name
     * @param {Array<{id:string,test:Function,required?:boolean}>} entries
     */
    setManifest(name, entries = []) {
      if (!name || !Array.isArray(entries)) return false;
      manifests.set(name, {
        name,
        entries: entries.filter((e) => e && typeof e.test === 'function' && e.id)
      });
      return true;
    },

    /**
     * Получить манифест
     * @param {string} name
     */
    getManifest(name) {
      return manifests.get(name) || null;
    },

    /**
     * Проверить манифест зависимостей
     * @param {string} name
     * @param {Object} options
     * @returns {{ok:boolean, missing:string[]}}
     */
    checkManifest(name, options = {}) {
      const manifest = manifests.get(name);
      if (!manifest) {
        const missing = [`manifest:${name}`];
        if (!options.silent) {
          trackModuleError(new Error('Missing manifest'), {
            source: 'heys_module_loader_v1.js',
            type: 'missing_manifest',
            missing
          });
        }
        return { ok: false, missing };
      }

      const missing = [];
      manifest.entries.forEach((entry) => {
        if (entry.required === false) return;
        let ok = false;
        try {
          ok = !!entry.test();
        } catch (e) {
          ok = false;
        }
        if (!ok) missing.push(entry.id);
      });

      if (missing.length > 0 && !options.silent) {
        trackModuleError(new Error('Missing manifest dependencies'), {
          source: 'heys_module_loader_v1.js',
          type: 'missing_manifest_deps',
          manifest: manifest.name,
          missing
        });
        return { ok: false, missing };
      }

      return { ok: true, missing: [] };
    },

    /**
     * Проверка критичных day-модулей
     * @returns {{ok:boolean, missing:string[]}}
     */
    checkDayDeps() {
      if (this.checkManifest) {
        return this.checkManifest('day');
      }
      const missing = [];

      if (!HEYS.dayUtils) missing.push('HEYS.dayUtils');
      if (!HEYS.dayHooks) missing.push('HEYS.dayHooks');
      if (!HEYS.dayPopups) missing.push('HEYS.dayPopups');
      if (!HEYS.dayGallery) missing.push('HEYS.dayGallery');
      if (!HEYS.mealScoring) missing.push('HEYS.mealScoring');

      if (!HEYS.dayComponents?.MealAddProduct) missing.push('HEYS.dayComponents.MealAddProduct');
      if (!HEYS.dayComponents?.ProductRow) missing.push('HEYS.dayComponents.ProductRow');
      if (!HEYS.dayComponents?.MealCard) missing.push('HEYS.dayComponents.MealCard');
      if (!HEYS.dayComponents?.AdviceCard) missing.push('HEYS.dayComponents.AdviceCard');

      if (!HEYS.dayMealsDisplay) missing.push('HEYS.dayMealsDisplay');
      if (!HEYS.dayMealsList) missing.push('HEYS.dayMealsList');

      if (missing.length > 0) {
        trackModuleError(new Error('Missing day module dependencies'), {
          source: 'heys_module_loader_v1.js',
          type: 'missing_day_deps',
          missing
        });
        return { ok: false, missing };
      }

      return { ok: true, missing: [] };
    }
  };

  HEYS.moduleLoader.setManifest('day', [
    { id: 'HEYS.dayUtils', test: () => !!HEYS.dayUtils },
    { id: 'HEYS.dayHooks', test: () => !!HEYS.dayHooks },
    { id: 'HEYS.dayPopups', test: () => !!HEYS.dayPopups },
    { id: 'HEYS.dayGallery', test: () => !!HEYS.dayGallery },
    { id: 'HEYS.mealScoring', test: () => !!HEYS.mealScoring },
    { id: 'HEYS.dayComponents.MealAddProduct', test: () => !!HEYS.dayComponents?.MealAddProduct },
    { id: 'HEYS.dayComponents.ProductRow', test: () => !!HEYS.dayComponents?.ProductRow },
    { id: 'HEYS.dayComponents.MealCard', test: () => !!HEYS.dayComponents?.MealCard },
    { id: 'HEYS.dayComponents.AdviceCard', test: () => !!HEYS.dayComponents?.AdviceCard },
    { id: 'HEYS.dayMealsDisplay', test: () => !!HEYS.dayMealsDisplay },
    { id: 'HEYS.dayMealsList', test: () => !!HEYS.dayMealsList }
  ]);

  /**
   * Загрузить скрипт с таймаутом
   * @param {string} src - Путь к скрипту
   * @param {number} timeout - Таймаут (мс)
   * @returns {Promise<void>}
   */
  function loadScript(src, timeout) {
    return new Promise((resolve, reject) => {
      const script = document.createElement('script');
      script.src = src;
      script.defer = true;

      // Таймаут
      const timeoutId = setTimeout(() => {
        script.remove();
        reject(new Error(`Timeout loading ${src}`));
      }, timeout);

      script.onload = () => {
        clearTimeout(timeoutId);
        resolve();
      };

      script.onerror = () => {
        clearTimeout(timeoutId);
        script.remove();
        reject(new Error(`Failed to load ${src}`));
      };

      document.head.appendChild(script);
    });
  }

  // Логирование инициализации
  if (window.DEV?.isDev?.()) {
    devLog('[ModuleLoader] Initialized');
  }
})();


/* ===== heys_bootstrap_v1.js ===== */
/**
 * HEYS App Initialization (Bootstrap) v1.0
 * =========================================
 * Application initialization utilities and dependency management
 * 
 * Features:
 * - Dependency waiting and detection
 * - React and HEYS core readiness checks
 * - Initialization retry logic with exponential backoff
 * - Loading UI management
 * - Error handling and timeout protection
 * - Client authorization utilities
 * - Curator session detection
 * 
 * Scientific Foundation:
 * - Progressive Enhancement (Aaron Gustafson, 2008)
 * - Defensive Programming
 * - Circuit Breaker Pattern (Michael Nygard)
 * 
 * @version 1.0.0
 * @feature-flag modular_bootstrap
 */

(function () {
  'use strict';

  const HEYS = window.HEYS = window.HEYS || {};

  // 🆕 Heartbeat для watchdog — bootstrap загружен
  window.__heysLoadingHeartbeat = Date.now();

  // Default feature flags (safe, local-only)
  HEYS.features = HEYS.features || {
    unifiedTables: true,
    extendedNutrients: true
  };

  // Check feature flag - если используется legacy mode, пропускаем модуль
  if (HEYS.featureFlags?.isEnabled('use_legacy_monolith')) {
    if (HEYS.featureFlags?.isEnabled('dev_module_logging')) {
      console.log('[Bootstrap] ⏭️ Skipped (legacy monolith mode)');
    }
    return;
  }

  // Performance tracking start
  HEYS.modulePerf?.startLoad('bootstrap');

  if (HEYS.featureFlags?.isEnabled('dev_module_logging')) {
    console.log('[Bootstrap] 📦 Loading module...');
  }

  // ============================================================================
  // CONSTANTS
  // ============================================================================

  const INIT_RETRY_DELAY = 100; // ms between dependency checks
  const MAX_INIT_RETRIES = 50; // max 50 retries = 5 seconds

  let reactCheckCount = 0;

  // ==========================================================================
  // STORAGE HELPERS (store-first + ¤Z¤)
  // ==========================================================================

  const tryParseStoredValue = (raw, fallback) => {
    if (raw === null || raw === undefined) return fallback;
    if (typeof raw === 'string') {
      let str = raw;
      if (str.startsWith('¤Z¤') && HEYS.store?.decompress) {
        try { str = HEYS.store.decompress(str); } catch (_) { }
      }
      try { return JSON.parse(str); } catch (_) { return str; }
    }
    return raw;
  };

  const readGlobalValue = (key, fallback) => {
    try {
      if (HEYS.store?.get) {
        const stored = HEYS.store.get(key, null);
        if (stored !== null && stored !== undefined) {
          return tryParseStoredValue(stored, fallback);
        }
      }
      const raw = localStorage.getItem(key);
      if (raw !== null && raw !== undefined) return tryParseStoredValue(raw, fallback);
      return fallback;
    } catch {
      return fallback;
    }
  };

  // ============================================================================
  // DEPENDENCY DETECTION
  // ============================================================================

  /**
   * Check if React is loaded and ready
   * @returns {boolean} true if React and ReactDOM are available
   */
  function isReactReady() {
    return !!(window.React && window.ReactDOM);
  }

  /**
   * Check if HEYS core modules are ready
   * @returns {boolean} true if required HEYS modules are loaded
   */
  function isHeysReady() {
    return !!(
      window.HEYS &&
      window.HEYS.core &&
      window.HEYS.store &&
      window.HEYS.YandexAPI
    );
  }

  // ============================================================================
  // LOADING UI
  // ============================================================================

  /**
   * Show minimal loading spinner
   */
  function showInitLoader() {
    if (document.getElementById('heys-init-loader')) return;

    const bootLog = (msg) => window.__heysLog && window.__heysLog('[DEPS] ' + msg);
    bootLog('showing loader (waiting for deps)');

    const loader = document.createElement('div');
    loader.id = 'heys-init-loader';
    loader.style.cssText = 'position:fixed;inset:0;display:flex;align-items:center;justify-content:center;background:#fff;z-index:99999';
    loader.innerHTML = '<div style="width:40px;height:40px;border:3px solid #e5e7eb;border-top-color:#10b981;border-radius:50%;animation:spin 0.8s linear infinite"></div><style>@keyframes spin{to{transform:rotate(360deg)}}</style>';
    document.body.appendChild(loader);
  }

  /**
   * Hide loading spinner
   */
  function hideInitLoader() {
    document.getElementById('heys-init-loader')?.remove();
  }

  /**
   * Show error message when initialization fails
   */
  function showInitError() {
    hideInitLoader();
    document.body.innerHTML = '<div style="padding:40px;text-align:center;font-family:system-ui"><h1>⚠️ Ошибка загрузки</h1><p>Не удалось загрузить приложение. Обновите страницу.</p><button onclick="location.reload()" style="margin-top:20px;padding:12px 24px;background:#10b981;color:white;border:none;border-radius:8px;font-size:16px;cursor:pointer">Обновить</button></div>';
  }

  // ============================================================================
  // DEPENDENCY WAITING
  // ============================================================================

  /**
   * Wait for dependencies with retry logic
   * @param {Function} onReady - Callback to execute when ready
   */
  function waitForDependencies(onReady) {
    const bootLog = (msg) => window.__heysLog && window.__heysLog('[DEPS] ' + msg);

    // Show loader after 200ms (2 checks)
    if (reactCheckCount === 2) {
      showInitLoader();
    }

    // Check if all dependencies are ready
    if (isReactReady() && isHeysReady()) {
      bootLog('deps ready, init app');
      hideInitLoader();
      reactCheckCount = 0; // Reset counter
      onReady();
      return;
    }

    reactCheckCount++;
    bootLog('waiting #' + reactCheckCount + ' React:' + isReactReady() + ' HEYS:' + isHeysReady());

    // Timeout protection - max 50 attempts (5 seconds)
    if (reactCheckCount > MAX_INIT_RETRIES) {
      console.error('[Bootstrap] ❌ Timeout waiting for dependencies!');
      console.error('[Bootstrap] React ready:', isReactReady());
      console.error('[Bootstrap] HEYS ready:', isHeysReady());
      bootLog('TIMEOUT! React:' + isReactReady() + ' HEYS:' + isHeysReady());

      showInitError();
      return;
    }

    // Retry after delay
    setTimeout(() => waitForDependencies(onReady), INIT_RETRY_DELAY);
  }

  // ============================================================================
  // AUTHORIZATION UTILITIES
  // ============================================================================

  /**
   * Check if current session is curator (vs client)
   * @returns {boolean} true if curator session
   */
  function isCuratorSession() {
    if (HEYS.auth?.isCuratorSession) return HEYS.auth.isCuratorSession();
    const curatorSession = readGlobalValue('heys_curator_session', null);
    if (curatorSession && curatorSession.length > 10) return true;
    const legacy = readGlobalValue('heys_supabase_auth_token', null);
    if (legacy?.access_token) return true;
    return !!HEYS.cloud?.getUser?.();
  }

  /**
   * Check if user is authorized as CLIENT (not curator, not guest)
   * @returns {boolean} true if client is authorized
   */
  function isClientAuthorized() {
    let clientId = null;

    // 1. Try heys_pin_auth_client first (for PIN auth)
    const pinAuthClient = readGlobalValue('heys_pin_auth_client', null);
    if (pinAuthClient && pinAuthClient.length > 10) {
      clientId = pinAuthClient;
    }

    // 2. Then try heys_client_current (for curator-managed clients)
    if (!clientId) {
      const raw = readGlobalValue('heys_client_current', null);
      if (raw) clientId = raw;
    }

    const isCurator = isCuratorSession();
    const result = clientId && clientId.length > 10 && !isCurator;

    if (HEYS.featureFlags?.isEnabled('dev_module_logging')) {
      console.log('[Bootstrap] isClientAuthorized:', {
        clientId: clientId ? 'present' : 'missing',
        length: clientId?.length,
        isCurator,
        result
      });
    }

    return result;
  }

  // ============================================================================
  // MODULE EXPORTS
  // ============================================================================

  // Export Bootstrap API to HEYS namespace
  HEYS.Bootstrap = {
    // Dependency detection
    isReactReady: isReactReady,
    isHeysReady: isHeysReady,

    // Initialization
    waitForDependencies: waitForDependencies,

    // Authorization
    isCuratorSession: isCuratorSession,
    isClientAuthorized: isClientAuthorized,

    // UI
    showInitLoader: showInitLoader,
    hideInitLoader: hideInitLoader,
    showInitError: showInitError,

    // Constants
    INIT_RETRY_DELAY: INIT_RETRY_DELAY,
    MAX_INIT_RETRIES: MAX_INIT_RETRIES
  };

  // Export to window for backward compatibility
  window.waitForDependencies = waitForDependencies;
  window.isReactReady = isReactReady;
  window.isHeysReady = isHeysReady;
  window.isCuratorSession = isCuratorSession;
  window.isClientAuthorized = isClientAuthorized;

  // Also export to legacy _tour namespace if it exists
  if (window.HEYS._tour) {
    window.HEYS._tour.isCuratorSession = isCuratorSession;
    window.HEYS._tour.isClientAuthorized = isClientAuthorized;
  }

  // Performance tracking end
  HEYS.modulePerf?.endLoad('bootstrap', true);

  if (HEYS.featureFlags?.isEnabled('dev_module_logging')) {
    console.log('[Bootstrap] ✅ Module loaded successfully');
  }
})();


/* ===== heys_platform_apis_v1.js ===== */
/**
 * HEYS Platform APIs v1.0
 * =======================
 * Modern Web Platform APIs integration for PWA functionality
 * 
 * Includes 16 Platform APIs:
 * - Service Worker (registration, updates, background sync)
 * - Storage Management (persistent storage, estimates)
 * - Device Capabilities (memory, CPU, network)
 * - Idle Detection (user return detection)
 * - Window Controls Overlay (desktop PWA)
 * - Barcode Detection (product scanning)
 * - Web Share API (content sharing)
 * - Contact Picker API
 * - Speech Recognition API
 * - Launch Handler API
 * - Protocol Handler API
 * - File System Access API
 * - Credential Management API
 * - Screen Orientation API
 * - Fullscreen API
 * - Vibration API
 * - Web Animations API
 * 
 * @version 1.0.0
 * @feature-flag modular_platform_apis
 */

(function () {
  'use strict';

  const HEYS = window.HEYS = window.HEYS || {};
  const DEV = window.DEV || {};
  const devLog = typeof DEV.log === 'function' ? DEV.log.bind(DEV) : function () { };
  const devWarn = typeof DEV.warn === 'function' ? DEV.warn.bind(DEV) : function () { };
  const devInfo = typeof DEV.info === 'function' ? DEV.info.bind(DEV) : function () { };
  const devDebug = typeof DEV.debug === 'function' ? DEV.debug.bind(DEV) : function () { };
  const trackError = (error, context) => {
    if (!HEYS?.analytics?.trackError) return;
    try {
      const err = error instanceof Error ? error : new Error(String(error || 'PlatformAPIs error'));
      HEYS.analytics.trackError(err, context);
    } catch (_) { }
  };
  const quietConsole = {
    trace: (...args) => { if (window.console && typeof window.console.trace === 'function') window.console.trace(...args); },
    log: (...args) => devLog(...args),
    info: (...args) => devInfo(...args),
    debug: (...args) => devDebug(...args),
    warn: (...args) => devWarn(...args),
    error: (...args) => {
      devWarn(...args);
      trackError(args[0], { scope: 'HEYS.PlatformAPIs', details: args.slice(1) });
    }
  };
  const console = quietConsole;

  // Check feature flag - если используется legacy mode, пропускаем модуль
  if (HEYS.featureFlags?.isEnabled('use_legacy_monolith')) {
    if (HEYS.featureFlags?.isEnabled('dev_module_logging')) {
      console.log('[PlatformAPIs] ⏭️ Skipped (legacy monolith mode)');
    }
    return;
  }

  // Performance tracking start
  HEYS.modulePerf?.startLoad('platform_apis');

  if (HEYS.featureFlags?.isEnabled('dev_module_logging')) {
    console.log('[PlatformAPIs] 📦 Loading module...');
  }

  // ============================================================================
  // EXTRACTED CODE FROM heys_app_v12.js (lines 481-2057)
  // ============================================================================

  // === Service Worker Registration (Production only) ===
  const UPDATE_BANNER_ID = 'heys-sw-update-banner';
  const OFFLINE_BANNER_ID = 'heys-offline-banner';
  const UPDATE_LOCK_KEY = 'heys_update_in_progress';
  const UPDATE_LOCK_TIMEOUT = 30000;
  const UPDATE_ATTEMPT_KEY = 'heys_update_attempt';
  const MAX_UPDATE_ATTEMPTS = 2;
  const UPDATE_COOLDOWN_MS = 60000;

  let _updateAvailable = false;
  let _updateVersion = null;

  function getAppVersion() {
    return HEYS.version || window.APP_VERSION || 'unknown';
  }

  // === Семантическое сравнение версий ===
  // Версия: YYYY.MM.DD.HHMM.hash → сравниваем числовую часть
  function isNewerVersion(serverVersion, currentVersion) {
    if (!serverVersion || !currentVersion) return false;
    if (serverVersion === currentVersion) return false;

    const extractNumeric = (v) => {
      const parts = v.split('.');
      if (parts.length < 4) return 0;
      return parseInt(parts.slice(0, 4).join(''), 10) || 0;
    };

    const serverNum = extractNumeric(serverVersion);
    const currentNum = extractNumeric(currentVersion);

    return serverNum > currentNum;
  }

  function isUpdateLocked() {
    try {
      const lockData = localStorage.getItem(UPDATE_LOCK_KEY);
      if (!lockData) return false;
      const { timestamp } = JSON.parse(lockData);
      if (Date.now() - timestamp > UPDATE_LOCK_TIMEOUT) {
        localStorage.removeItem(UPDATE_LOCK_KEY);
        return false;
      }
      return true;
    } catch {
      return false;
    }
  }

  function setUpdateLock() {
    localStorage.setItem(UPDATE_LOCK_KEY, JSON.stringify({ timestamp: Date.now() }));
  }

  function clearUpdateLock() {
    localStorage.removeItem(UPDATE_LOCK_KEY);
  }

  function showUpdateBadge(version) {
    _updateAvailable = true;
    _updateVersion = version;

    document.getElementById('heys-update-badge')?.remove();

    const badge = document.createElement('div');
    badge.id = 'heys-update-badge';
    badge.className = 'heys-update-badge';

    const button = document.createElement('button');
    button.id = 'heys-update-badge-btn';
    button.type = 'button';
    button.className = 'heys-update-badge__btn';
    button.innerHTML = `
      <span class="heys-update-badge__emoji">🆕</span>
      <span class="heys-update-badge__label">Обновить HEYS</span>
      <span class="heys-update-badge__version">v${version?.split('.').slice(0, 3).join('.') || 'new'}</span>
    `;
    button.addEventListener('click', () => installUpdate());

    badge.appendChild(button);
    document.body.appendChild(badge);

    if (navigator.vibrate) navigator.vibrate(50);
  }

  function hideUpdateBadge() {
    _updateAvailable = false;
    _updateVersion = null;

    const badge = document.getElementById('heys-update-badge');
    if (badge) {
      badge.classList.add('heys-update-badge--hide');
      setTimeout(() => badge.remove(), 300);
    }
  }

  function getProgressClass(progress) {
    const value = Number(progress) || 0;
    return `heys-update-modal__progress-bar--${value}`;
  }

  function showUpdateModal(stage = 'checking') {
    document.getElementById('heys-update-modal')?.remove();

    const stages = {
      checking: { icon: '🔍', title: 'Проверка обновлений', subtitle: 'Подождите...', isSpinner: false },
      found: { icon: '🆕', title: 'Найдено обновление!', subtitle: 'Загружаем новую версию...', isSpinner: false },
      downloading: { icon: '📥', title: 'Загрузка', subtitle: 'Это займёт пару секунд...', isSpinner: false },
      installing: { icon: '⚙️', title: 'Установка', subtitle: 'Почти готово...', isSpinner: false },
      ready: { icon: '✨', title: 'Готово!', subtitle: 'Приложение обновлено', isSpinner: false },
      reloading: { icon: 'spinner', title: 'Перезагрузка', subtitle: 'Применяем изменения...', isSpinner: true }
    };

    const s = stages[stage] || stages.checking;

    const iconHtml = `
      <div id="heys-update-icon" class="heys-update-modal__icon ${s.isSpinner ? 'is-spinner' : ''}">
        ${s.isSpinner ? '<div class="heys-update-modal__spinner"></div>' : s.icon}
      </div>
    `;

    const progressWidth = stage === 'checking'
      ? '20%'
      : stage === 'found'
        ? '40%'
        : stage === 'downloading'
          ? '60%'
          : stage === 'installing'
            ? '80%'
            : '100%';

    const progressValue = parseInt(progressWidth, 10) || 0;
    const progressClass = getProgressClass(progressValue);

    const progressHtml = `
      <div class="heys-update-modal__progress">
        <div id="heys-update-progress" class="heys-update-modal__progress-bar ${progressClass}"></div>
      </div>
    `;

    const footerHtml = `<p class="heys-update-modal__version">Версия ${getAppVersion()}</p>`;

    return renderUpdateDialog({
      dialogType: 'modal',
      id: 'heys-update-modal',
      rootClass: 'heys-update-modal',
      backdropClass: 'heys-update-modal__backdrop',
      cardClass: 'heys-update-modal__card',
      cardAttrs: 'role="dialog" aria-modal="true" aria-labelledby="heys-update-title" aria-describedby="heys-update-subtitle"',
      iconHtml,
      titleId: 'heys-update-title',
      titleClass: 'heys-update-modal__title',
      title: s.title,
      textId: 'heys-update-subtitle',
      textClass: 'heys-update-modal__subtitle',
      text: s.subtitle,
      progressHtml,
      footerHtml,
    });
  }

  function updateModalStage(stage) {
    const stages = {
      checking: { icon: '🔍', title: 'Проверка обновлений', subtitle: 'Подождите...', progress: 20, isSpinner: false },
      found: { icon: '🆕', title: 'Найдено обновление!', subtitle: 'Загружаем новую версию...', progress: 40, isSpinner: false },
      downloading: { icon: '📥', title: 'Загрузка', subtitle: 'Это займёт пару секунд...', progress: 60, isSpinner: false },
      installing: { icon: '⚙️', title: 'Установка', subtitle: 'Почти готово...', progress: 80, isSpinner: false },
      ready: { icon: '✨', title: 'Готово!', subtitle: 'Приложение обновлено', progress: 100, isSpinner: false },
      reloading: { icon: 'spinner', title: 'Перезагрузка', subtitle: 'Применяем изменения...', progress: 100, isSpinner: true }
    };

    const s = stages[stage];
    if (!s) return;

    const icon = document.getElementById('heys-update-icon');
    const title = document.getElementById('heys-update-title');
    const subtitle = document.getElementById('heys-update-subtitle');
    const progress = document.getElementById('heys-update-progress');

    if (icon) {
      if (s.isSpinner) {
        icon.innerHTML = '<div class="heys-update-modal__spinner"></div>';
        icon.classList.add('is-spinner');
      } else {
        icon.textContent = s.icon;
        icon.innerHTML = s.icon;
        icon.classList.remove('is-spinner');
      }
    }
    if (title) title.textContent = s.title;
    if (subtitle) subtitle.textContent = s.subtitle;
    if (progress) {
      progress.className = `heys-update-modal__progress-bar ${getProgressClass(s.progress)}`;
    }
  }

  function hideUpdateModal() {
    const modal = document.getElementById('heys-update-modal');
    if (modal) {
      modal.classList.add('heys-update-modal--hide');
      releaseUpdateDialogFocus(modal);
      setTimeout(() => modal.remove(), 300);
    }
  }

  function showManualRefreshPrompt(targetVersion) {
    document.getElementById('heys-update-modal')?.remove();

    const isIOS = /iPad|iPhone|iPod/.test(navigator.userAgent);

    const iconHtml = '<div class="heys-update-prompt__spinner"></div>';
    const text = isIOS
      ? 'Закройте приложение и откройте заново для обновления до v' + targetVersion
      : 'Нажмите кнопку для обновления до v' + targetVersion;

    const actionsHtml = `${isIOS ? '' : `
      <button id="heys-manual-update-btn" class="heys-update-prompt__btn heys-update-prompt__btn--primary">Обновить сейчас</button>
    `}
      <button id="heys-update-later-btn" class="heys-update-prompt__btn heys-update-prompt__btn--ghost">Позже</button>
    `;

    const modal = renderUpdateDialog({
      dialogType: 'prompt',
      id: 'heys-update-modal',
      rootClass: 'heys-update-prompt',
      backdropClass: 'heys-update-prompt__backdrop',
      cardClass: 'heys-update-prompt__card',
      cardAttrs: 'role="dialog" aria-modal="true" aria-labelledby="heys-update-prompt-title" aria-describedby="heys-update-prompt-text"',
      iconHtml,
      titleId: 'heys-update-prompt-title',
      titleClass: 'heys-update-prompt__title',
      title: 'Требуется обновление',
      textId: 'heys-update-prompt-text',
      textClass: 'heys-update-prompt__text',
      text,
      footerHtml: actionsHtml,
    });

    const updateBtn = document.getElementById('heys-manual-update-btn');
    if (updateBtn) {
      updateBtn.addEventListener('click', () => {
        localStorage.removeItem(UPDATE_ATTEMPT_KEY);
        const url = new URL(window.location.href);
        url.searchParams.set('_v', Date.now().toString());
        window.location.href = url.toString();
      });
    }

    const laterBtn = document.getElementById('heys-update-later-btn');
    if (laterBtn) {
      laterBtn.addEventListener('click', () => {
        releaseUpdateDialogFocus(modal);
        modal?.remove();
      });
    }
  }

  function renderUpdateDialog({
    dialogType,
    id,
    rootClass,
    backdropClass,
    cardClass,
    cardAttrs,
    iconHtml = '',
    titleId,
    titleClass,
    title,
    textId,
    textClass,
    text,
    progressHtml = '',
    footerHtml = '',
  }) {
    const modal = document.createElement('div');
    modal.id = id;
    modal.className = rootClass;
    if (dialogType) {
      modal.dataset.updateDialog = dialogType;
    }

    const titleHtml = title
      ? `<h2 id="${titleId}" class="${titleClass}">${title}</h2>`
      : '';
    const textHtml = text
      ? `<p id="${textId}" class="${textClass}">${text}</p>`
      : '';

    modal.innerHTML = `
      <div class="${backdropClass}">
        <div class="${cardClass}" ${cardAttrs || ''}>
          ${iconHtml}
          ${titleHtml}
          ${textHtml}
          ${progressHtml}
          ${footerHtml}
        </div>
      </div>
    `;

    document.body.appendChild(modal);
    trapUpdateDialogFocus(modal);
    return modal;
  }

  function trapUpdateDialogFocus(modal) {
    if (!modal) return;

    const focusables = getFocusableElements(modal);
    const previousActive = document.activeElement instanceof HTMLElement ? document.activeElement : null;

    const focusTarget = focusables[0] || modal.querySelector('[role="dialog"]') || modal;
    if (focusTarget && typeof focusTarget.focus === 'function') {
      setTimeout(() => {
        try {
          focusTarget.focus({ preventScroll: true });
        } catch (_) {
          focusTarget.focus();
        }
      }, 0);
    }

    const handleKeydown = (event) => {
      if (event.key !== 'Tab') return;

      const items = getFocusableElements(modal);
      if (items.length === 0) {
        event.preventDefault();
        return;
      }

      const first = items[0];
      const last = items[items.length - 1];
      const isShift = event.shiftKey;
      const active = document.activeElement;

      if (isShift && active === first) {
        event.preventDefault();
        last.focus();
      } else if (!isShift && active === last) {
        event.preventDefault();
        first.focus();
      }
    };

    modal.addEventListener('keydown', handleKeydown);
    modal._heysFocusTrap = { previousActive, handleKeydown };
  }

  function releaseUpdateDialogFocus(modal) {
    const trap = modal?._heysFocusTrap;
    if (!trap) return;

    modal.removeEventListener('keydown', trap.handleKeydown);
    if (trap.previousActive && typeof trap.previousActive.focus === 'function') {
      try {
        trap.previousActive.focus({ preventScroll: true });
      } catch (_) {
        trap.previousActive.focus();
      }
    }
    delete modal._heysFocusTrap;
  }

  function getFocusableElements(container) {
    if (!container) return [];
    const selectors = [
      'a[href]:not([tabindex="-1"])',
      'button:not([disabled]):not([tabindex="-1"])',
      'input:not([disabled]):not([type="hidden"]):not([tabindex="-1"])',
      'select:not([disabled]):not([tabindex="-1"])',
      'textarea:not([disabled]):not([tabindex="-1"])',
      '[tabindex]:not([tabindex="-1"])'
    ];
    return Array.from(container.querySelectorAll(selectors.join(',')))
      .filter((el) => el instanceof HTMLElement && !el.hasAttribute('disabled'));
  }

  function installUpdate() {
    hideUpdateBadge();
    showUpdateModal('found');
    setTimeout(() => updateModalStage('downloading'), 800);
    setTimeout(() => updateModalStage('installing'), 1600);
    setTimeout(() => {
      updateModalStage('reloading');
      forceUpdateAndReload(false);
    }, 2400);
  }

  function getNetworkQuality() {
    const connection = navigator.connection || navigator.mozConnection || navigator.webkitConnection;
    if (!connection) return { type: 'unknown', quality: 'good' };

    const effectiveType = connection.effectiveType;
    const downlink = connection.downlink;
    const rtt = connection.rtt;

    let quality = 'good';
    if (effectiveType === 'slow-2g' || effectiveType === '2g' || rtt > 500) {
      quality = 'poor';
    } else if (effectiveType === '3g' || rtt > 200 || downlink < 1) {
      quality = 'moderate';
    }

    return { type: effectiveType || 'unknown', downlink, rtt, quality, saveData: connection.saveData };
  }

  async function smartVersionCheck() {
    const network = getNetworkQuality();

    if (network.quality === 'poor' || network.saveData) {
      return;
    }

    try {
      const hasUpdate = await checkServerVersion(true);

      if (hasUpdate) {
        showUpdateBadge(_updateVersion);
      }
    } catch (e) {
      return;
    }
  }

  async function checkServerVersion(silent = true) {
    try {
      const cacheBust = Date.now();
      const response = await fetch(`/build-meta.json?_cb=${cacheBust}`, {
        cache: 'no-store',
        headers: { 'Cache-Control': 'no-cache' }
      });

      if (!response.ok) return false;

      const data = await response.json();
      const currentVersion = getAppVersion();

      if (data.version && isNewerVersion(data.version, currentVersion)) {
        _updateVersion = data.version;

        const attempt = JSON.parse(localStorage.getItem(UPDATE_ATTEMPT_KEY) || '{}');
        const now = Date.now();

        if (attempt.timestamp && (now - attempt.timestamp) < UPDATE_COOLDOWN_MS) {
          return false;
        }

        if (attempt.targetVersion === data.version) {
          attempt.count = (attempt.count || 0) + 1;
        } else {
          attempt.targetVersion = data.version;
          attempt.count = 1;
        }
        attempt.timestamp = now;
        localStorage.setItem(UPDATE_ATTEMPT_KEY, JSON.stringify(attempt));

        if (attempt.count > MAX_UPDATE_ATTEMPTS) {
          showManualRefreshPrompt(data.version);
          return true;
        }

        if (isUpdateLocked()) {
          return true;
        }
        setUpdateLock();

        showUpdateModal('found');
        setTimeout(() => updateModalStage('downloading'), 1200);
        setTimeout(() => updateModalStage('installing'), 2400);
        setTimeout(() => {
          updateModalStage('reloading');
          forceUpdateAndReload(false);
        }, 3600);

        setTimeout(() => {
          const modal = document.getElementById('heys-update-modal');
          if (modal) {
            hideUpdateModal();
            clearUpdateLock();
          }
        }, 12000);

        return true;
      } else if (data.version && data.version !== currentVersion) {
        return false;
      }

      return false;
    } catch (e) {
      return false;
    }
  }

  function createSystemBanner({ id, className, text, actions }) {
    if (!document?.body || document.getElementById(id)) return;

    const banner = document.createElement('div');
    banner.id = id;
    banner.className = className;

    const textEl = document.createElement('span');
    textEl.className = 'heys-system-banner__text';
    textEl.textContent = text;
    banner.appendChild(textEl);

    if (Array.isArray(actions) && actions.length > 0) {
      const actionsEl = document.createElement('div');
      actionsEl.className = 'heys-system-banner__actions';
      actions.forEach((action) => {
        const btn = document.createElement('button');
        btn.type = 'button';
        btn.className = action.className;
        btn.textContent = action.label;
        btn.addEventListener('click', action.onClick);
        actionsEl.appendChild(btn);
      });
      banner.appendChild(actionsEl);
    }

    document.body.appendChild(banner);
  }

  function showUpdateNotification() {
    createSystemBanner({
      id: UPDATE_BANNER_ID,
      className: 'heys-system-banner heys-system-banner--update',
      text: 'Доступно обновление приложения',
      actions: [
        {
          label: '🔄 Обновить',
          className: 'heys-system-banner__btn heys-system-banner__btn--primary',
          onClick: () => {
            triggerSkipWaiting({
              fallbackMs: 5000,
              showModal: true,
              source: 'update-banner',
            });
          }
        },
        {
          label: '✕',
          className: 'heys-system-banner__btn heys-system-banner__btn--ghost',
          onClick: () => {
            const banner = document.getElementById(UPDATE_BANNER_ID);
            if (banner) banner.remove();
          }
        }
      ]
    });
  }

  function showOfflineNotification() {
    createSystemBanner({
      id: OFFLINE_BANNER_ID,
      className: 'heys-system-banner heys-system-banner--offline',
      text: '📴 Офлайн режим — данные сохраняются локально',
      actions: []
    });
  }

  function hideOfflineNotification() {
    const banner = document.getElementById(OFFLINE_BANNER_ID);
    if (banner) banner.remove();
  }

  function registerServiceWorker() {
    const bootLog = (msg) => window.__heysLog && window.__heysLog('[SW] ' + msg);

    if (!('serviceWorker' in navigator)) {
      bootLog('not supported');
      return;
    }

    // ❌ НЕ регистрируем SW на localhost — мешает разработке (HMR, updatefound и т.д.)
    if (window.location.hostname === 'localhost' || window.location.hostname === '127.0.0.1') {
      console.log('[SW] ⏭️ Skipped on localhost (dev mode)');
      bootLog('skipped (localhost)');
      // Удаляем существующий SW если есть (чтобы не мешал разработке)
      navigator.serviceWorker.getRegistrations().then(registrations => {
        registrations.forEach(reg => {
          reg.unregister().then(() => {
            console.log('[SW] 🗑️ Unregistered SW on localhost');
          });
        });
      });
      return;
    }

    bootLog('registering...');
    navigator.serviceWorker.register('/sw.js')
      .then((registration) => {
        console.log('[SW] ✅ Registered successfully');

        // Сохраняем регистрацию для Background Sync
        window.swRegistration = registration;

        // Background Sync — регистрируем при изменениях данных
        window.requestBackgroundSync = function () {
          if ('sync' in registration) {
            registration.sync.register('heys-sync')
              .then(function () { console.log('[SW] Background sync scheduled'); })
              .catch(function () { /* Background sync not available */ });
          }
        };

        // 🆕 Periodic Background Sync — автоматическая проверка обновлений в фоне
        // (раз в час когда приложение не активно, с WiFi)
        if ('periodicSync' in registration) {
          (async () => {
            try {
              const status = await navigator.permissions.query({ name: 'periodic-background-sync' });
              if (status.state === 'granted') {
                await registration.periodicSync.register('heys-periodic-update', {
                  minInterval: 60 * 60 * 1000, // 1 час
                });
                console.log('[SW] ⏰ Periodic Background Sync registered (1h)');
              }
            } catch (e) {
              console.log('[SW] Periodic Background Sync not supported');
            }
          })();
        }

        // Слушаем сообщения от SW (включая UPDATE_AVAILABLE)
        navigator.serviceWorker.addEventListener('message', (event) => {
          if (event.data?.type === 'UPDATE_AVAILABLE') {
            console.log('[SW] 🆕 Background update detected:', event.data.version);
            showUpdateBadge(event.data.version);
            showUpdateNotification();
          }
          if (event.data?.type === 'UPDATE_REQUIRED') {
            console.log('[SW] 🧭 Version mismatch — forcing update:', event.data.version);
            if (typeof HEYS.forceCheckAndUpdate === 'function') {
              HEYS.forceCheckAndUpdate();
            } else {
              triggerSkipWaiting({
                fallbackMs: 5000,
                showModal: true,
                source: 'update-required',
              });
            }
          }
          if (event.data?.type === 'CACHES_CLEARED') {
            // 🔒 Guard: если update_checks управляет lifecycle, не делаем reload отсюда.
            // update_checks сам вызовет triggerSkipWaiting → controllerchange → cache-busted reload.
            const managedByChecks = sessionStorage.getItem('heys_update_managed_by_checks') === 'true';
            if (managedByChecks) {
              console.log('[SW] ✅ Caches cleared — lifecycle managed by update_checks, skipping reload here');
              try { sessionStorage.removeItem('heys_update_managed_by_checks'); } catch (e) { }
              return;
            }

            const requiresLogout = sessionStorage.getItem('heys_update_requires_logout') === 'true';
            console.log('[SW] ✅ Caches cleared — resetting session for fresh data from cloud');

            if (requiresLogout) {
              // ✅ Guard для хуков — показываем экран выхода до очистки
              window.HEYS = window.HEYS || {};
              window.HEYS._isLoggingOut = true;
            }

            // 🔄 Сброс сессии ТОЛЬКО при апдейте
            // ⚠️ КРИТИЧНО: НЕ очищаем localStorage.clear() — это удаляет heys_products!
            // Вместо этого удаляем только сессионные ключи, сохраняя критические данные
            if (requiresLogout) {
              try {
                // 1. Завершаем auth сессию (если есть)
                if (HEYS.cloud?.signOut) {
                  HEYS.cloud.signOut();
                }

                // 2. Удаляем только сессионные данные, НЕ трогая products/profile
                // ❌ БЫЛО: localStorage.clear(); — удаляло ВСЮ базу продуктов!
                // ✅ СТАЛО: выборочная очистка
                const keysToRemove = [];
                const keysToKeep = ['heys_products', 'heys_profile', 'heys_norms', 'heys_hr_zones'];

                for (let i = 0; i < localStorage.length; i++) {
                  const key = localStorage.key(i);
                  // Сохраняем критические ключи и данные дней
                  if (!keysToKeep.some(k => key.includes(k)) && !key.startsWith('heys_dayv2_')) {
                    keysToRemove.push(key);
                  }
                }

                keysToRemove.forEach(key => localStorage.removeItem(key));
                console.log(`[SW] 🗑️ Removed ${keysToRemove.length} session keys, kept critical data`);

                // 3. Очищаем sessionStorage полностью (там только кэш)
                sessionStorage.clear();

                console.log('[SW] ✅ Session cleared safely, reloading...');
              } catch (e) {
                console.warn('[SW] Session clear error:', e);
              }
            }

            // Сбрасываем маркер после обработки
            try {
              sessionStorage.removeItem('heys_update_requires_logout');
            } catch (e) { }

            // 4. Перезагружаем страницу с cache-busting — пользователь увидит экран входа
            setTimeout(() => {
              const url = new URL(window.location.href);
              url.searchParams.set('_v', Date.now().toString());
              window.location.href = url.toString();
            }, 100);
          }
        });

        // Проверяем обновления каждые 60 секунд
        setInterval(() => {
          registration.update().catch(() => { });
        }, 60000);

        // Слушаем обновления
        registration.addEventListener('updatefound', () => {
          const newWorker = registration.installing;
          console.log('[SW] 🔄 New version downloading...');

          // 🔒 Показываем модалку ТОЛЬКО если это реальное обновление (есть предыдущий SW)
          // Используем registration.active — он показывает есть ли АКТИВНЫЙ SW до этого
          // controller может быть null если страница загружена до активации SW
          const hasExistingSW = registration.active || navigator.serviceWorker.controller;
          if (!hasExistingSW) {
            console.log('[SW] First-time install, no update modal needed');
            return;
          }

          console.log('[SW] 🆕 Update detected! Existing SW:', registration.active?.state || 'controller');

          // Предотвращаем дублирование обновления (надёжный флаг в localStorage)
          if (isUpdateLocked()) {
            console.log('[SW] Update already in progress (locked), skipping');
            return;
          }

          // 🔒 Устанавливаем флаг ДО показа модалки — это реальное обновление
          sessionStorage.setItem('heys_pending_update', 'true');
          setUpdateLock();

          // Показываем UI обновления
          showUpdateModal('downloading');

          // 🔒 Fallback: если через 10 секунд модалка ещё на экране — убираем
          const swUpdateTimeout = setTimeout(() => {
            const modal = document.getElementById('heys-update-modal');
            if (modal) {
              console.warn('[SW] Update modal timeout, hiding...');
              hideUpdateModal();
              clearUpdateLock();
            }
          }, 10000);

          newWorker?.addEventListener('statechange', () => {
            if (newWorker.state === 'installed') {
              console.log('[SW] 🎉 New version ready!');
              clearTimeout(swUpdateTimeout); // Отменяем fallback
              // Упрощённая анимация: ready → reloading → reload
              updateModalStage('ready');
              setTimeout(() => {
                updateModalStage('reloading');
                forceUpdateAndReload(false);
              }, 800);
            }
          });
        });
      })
      .catch((error) => {
        console.log('[SW] ❌ Registration failed', error);
      });

    // Слушаем сообщения от SW
    navigator.serviceWorker.addEventListener('message', (event) => {
      if (event.data?.type === 'SYNC_START' && window.HEYS?.cloud?.sync) {
        window.HEYS.cloud.sync();
      }
      if (event.data?.type === 'SYNC_COMPLETE') {
        window.dispatchEvent(new CustomEvent('heys:sync-complete'));
      }
    });

    // Offline/Online banner
    window.addEventListener('offline', showOfflineNotification);
    window.addEventListener('online', hideOfflineNotification);
    if (navigator.onLine === false) {
      showOfflineNotification();
    }

    // Слушаем контроллер изменений (когда SW взял контроль)
    // ✅ АВТОМАТИЧЕСКИЙ reload при смене SW для бесшовного обновления PWA
    let refreshing = false;
    let hadControllerBefore = !!navigator.serviceWorker.controller;

    navigator.serviceWorker.addEventListener('controllerchange', () => {
      console.log('[SW] Controller changed — new SW activated!');
      if (refreshing) return;

      // 🔒 Показываем модалку и делаем reload ТОЛЬКО если это реальное обновление
      // Реальное обновление: был контроллер до этого ИЛИ есть флаг pending_update
      const isRealUpdate = hadControllerBefore ||
        sessionStorage.getItem('heys_pending_update') === 'true' ||
        isUpdateLocked();

      console.log('[SW] Update check:', { hadControllerBefore, isRealUpdate });

      if (isRealUpdate) {
        // Реальное обновление — показываем модалку и делаем reload
        refreshing = true;
        showUpdateModal('reloading');

        // v61/v62: Defer reload until active sync completes (prevents mid-sync page interruption)
        const doReload = () => {
          console.info('[SW] 🔄 Reloading page with new SW... (triggered by controllerchange)');
          const url = new URL(window.location.href);
          url.searchParams.set('_v', Date.now().toString());
          window.location.href = url.toString();
        };
        const syncInFlight = typeof HEYS !== 'undefined' && HEYS.cloud && typeof HEYS.cloud.isSyncing === 'function'
          ? HEYS.cloud.isSyncing()
          : null;
        // v62: Also check _authSyncPending — set SYNCHRONOUSLY in PIN auth restore BEFORE
        // cloud.syncClient() is called (covers the race window where _syncInFlight isn't set yet).
        const authPending = typeof HEYS !== 'undefined' && HEYS.cloud && typeof HEYS.cloud.isAuthSyncPending === 'function'
          ? HEYS.cloud.isAuthSyncPending()
          : false;
        if (syncInFlight) {
          console.info('[SW] ⏳ Sync in progress — deferring reload until sync completes (max 15s)...');
          Promise.race([
            syncInFlight,
            new Promise(resolve => setTimeout(resolve, 15000))
          ]).finally(doReload);
        } else if (authPending) {
          // v62: Auth sync is about to start (PIN restore fire-and-forget race).
          // Poll until syncClient creates _syncInFlight, then defer to it.
          console.info('[SW] ⏳ Auth sync pending — polling for sync start (max 15s)...');
          const deadline = Date.now() + 15000;
          const pollId = setInterval(() => {
            const inflightNow = typeof HEYS !== 'undefined' && HEYS.cloud?.isSyncing?.();
            if (inflightNow) {
              clearInterval(pollId);
              console.info('[SW] ⏳ Sync detected after auth — deferring reload...');
              Promise.race([
                inflightNow,
                new Promise(resolve => setTimeout(resolve, 15000))
              ]).finally(doReload);
            } else if (!HEYS.cloud?.isAuthSyncPending?.() || Date.now() > deadline) {
              clearInterval(pollId);
              doReload();
            }
          }, 500); // perf: 500ms достаточно для polling sync state, 200ms создавал лишнюю нагрузку
        } else {
          setTimeout(doReload, 500);
        }
      } else {
        // Первичная установка SW — НЕ делаем reload, страница уже загружена
        console.log('[SW] First-time controller activation, no reload needed');
      }
    });
  }

  // === Централизованная функция skipWaiting с debounce и проверками ===
  let _skipWaitingInProgress = false;
  const SKIP_WAITING_DEBOUNCE_MS = 500;

  async function triggerSkipWaiting(options = {}) {
    const { fallbackMs = 5000, showModal = false, source = 'unknown' } = options;

    // Debounce: предотвращаем множественные вызовы
    if (_skipWaitingInProgress) {
      console.log('[SW] ⏳ skipWaiting already in progress, skipping duplicate from:', source);
      return false;
    }

    _skipWaitingInProgress = true;
    console.log('[SW] 🔄 triggerSkipWaiting called from:', source);

    try {
      // 1. Проверяем наличие SW controller
      if (!navigator.serviceWorker?.controller) {
        console.warn('[SW] ⚠️ No active SW controller — skipping skipWaiting');
        return false;
      }

      // 2. Проверяем есть ли waiting SW (новая версия готова)
      const registration = await navigator.serviceWorker.getRegistration();
      if (registration?.waiting) {
        console.log('[SW] ✅ Found waiting SW — sending skipWaiting');
        registration.waiting.postMessage({ type: 'SKIP_WAITING' });
      } else {
        // Fallback: отправляем на controller (для старого формата)
        console.log('[SW] ⚠️ No waiting SW found — sending to controller (legacy)');
        navigator.serviceWorker.controller.postMessage('skipWaiting');
      }

      // 3. Устанавливаем флаги для корректного reload
      sessionStorage.setItem('heys_pending_update', 'true');
      sessionStorage.setItem('heys_force_sync_after_update', 'true');

      // 4. Показываем модал если нужно
      if (showModal && typeof showUpdateModal === 'function') {
        showUpdateModal('reloading');
      }

      // 5. Fallback таймер (если controllerchange не сработает)
      setTimeout(() => {
        if (sessionStorage.getItem('heys_pending_update') === 'true') {
          console.log('[SW] ⚡ Fallback reload after', fallbackMs, 'ms (triggered by triggerSkipWaiting fallback)');
          const url = new URL(window.location.href);
          url.searchParams.set('_v', Date.now().toString());
          window.location.href = url.toString();
        }
      }, fallbackMs);

      return true;
    } catch (err) {
      console.error('[SW] ❌ triggerSkipWaiting error:', err);
      return false;
    } finally {
      // Сброс debounce через заданное время
      setTimeout(() => {
        _skipWaitingInProgress = false;
      }, SKIP_WAITING_DEBOUNCE_MS);
    }
  }

  // === Принудительное обновление ===
  function forceUpdateAndReload(showModal = true) {

    if (showModal) {
      showUpdateModal('reloading');
    }

    // Используем централизованную функцию с debounce и проверками
    triggerSkipWaiting({
      fallbackMs: 5000,
      showModal: false, // модал уже показан выше
      source: 'forceUpdateAndReload'
    });
  }

  // === Persistent Storage API ===
  // Защищает данные приложения от автоматического удаления браузером при нехватке места
  // Это критически важно для PWA с офлайн-данными
  async function requestPersistentStorage() {
    if (!navigator.storage?.persist) {
      console.log('[Storage] Persistent Storage API not supported');
      return false;
    }

    try {
      // Проверяем текущий статус
      const isPersisted = await navigator.storage.persisted();

      if (isPersisted) {
        console.log('[Storage] ✅ Already persistent');
        return true;
      }

      // Запрашиваем постоянное хранение
      const granted = await navigator.storage.persist();

      if (granted) {
        console.log('[Storage] ✅ Persistent storage granted!');
        // Вибрация-подтверждение
        if (navigator.vibrate) navigator.vibrate([50, 30, 50]);
        return true;
      } else {
        console.log('[Storage] ⚠️ Persistent storage denied by browser');
        return false;
      }
    } catch (e) {
      console.error('[Storage] Error requesting persistence:', e);
      return false;
    }
  }

  // Storage Estimate — показывает сколько места используется
  async function getStorageEstimate() {
    if (!navigator.storage?.estimate) {
      return { usage: 0, quota: 0, usageDetails: {} };
    }

    try {
      const estimate = await navigator.storage.estimate();
      const usageMB = (estimate.usage / (1024 * 1024)).toFixed(2);
      const quotaMB = (estimate.quota / (1024 * 1024)).toFixed(2);
      const usagePercent = ((estimate.usage / estimate.quota) * 100).toFixed(1);

      console.log(`[Storage] 📊 Usage: ${usageMB}MB / ${quotaMB}MB (${usagePercent}%)`);

      // Детализация по типам (если доступна)
      if (estimate.usageDetails) {
        Object.entries(estimate.usageDetails).forEach(([key, value]) => {
          console.log(`[Storage]   - ${key}: ${(value / (1024 * 1024)).toFixed(2)}MB`);
        });
      }

      return {
        usage: estimate.usage,
        quota: estimate.quota,
        usageMB: parseFloat(usageMB),
        quotaMB: parseFloat(quotaMB),
        usagePercent: parseFloat(usagePercent),
        usageDetails: estimate.usageDetails || {}
      };
    } catch (e) {
      console.error('[Storage] Error getting estimate:', e);
      return { usage: 0, quota: 0, usageDetails: {} };
    }
  }

  // Экспортируем для использования в приложении
  HEYS.storage = HEYS.storage || {};
  HEYS.storage.requestPersistent = requestPersistentStorage;
  HEYS.storage.getEstimate = getStorageEstimate;

  // Запрашиваем Persistent Storage автоматически после первого использования
  // (когда есть данные, которые стоит защитить)
  setTimeout(async () => {
    // Проверяем, есть ли у нас значимые данные
    const hasLocalData = Object.keys(localStorage).some(k => k.startsWith('heys_'));
    if (hasLocalData) {
      await requestPersistentStorage();
    }
  }, 5000);

  // === Device Capabilities API ===
  // Определяем возможности устройства для адаптивной производительности
  function getDeviceCapabilities() {
    const capabilities = {
      // Память устройства (GB) — используем для адаптации размера кэша
      memory: navigator.deviceMemory || 4, // fallback 4GB

      // Количество логических процессоров — для Web Workers
      cores: navigator.hardwareConcurrency || 4,

      // Тип соединения
      connection: navigator.connection ? {
        type: navigator.connection.effectiveType || 'unknown',
        downlink: navigator.connection.downlink || 0,
        rtt: navigator.connection.rtt || 0,
        saveData: navigator.connection.saveData || false
      } : { type: 'unknown', downlink: 0, rtt: 0, saveData: false },

      // Размер экрана
      screen: {
        width: window.screen.width,
        height: window.screen.height,
        pixelRatio: window.devicePixelRatio || 1,
        colorDepth: window.screen.colorDepth || 24
      },

      // Touch capabilities
      hasTouch: 'ontouchstart' in window || navigator.maxTouchPoints > 0,
      maxTouchPoints: navigator.maxTouchPoints || 0,

      // Платформа
      platform: navigator.platform || 'unknown',
      isStandalone: window.matchMedia('(display-mode: standalone)').matches,

      // Предпочтения пользователя
      prefersReducedMotion: window.matchMedia('(prefers-reduced-motion: reduce)').matches,
      prefersColorScheme: window.matchMedia('(prefers-color-scheme: dark)').matches ? 'dark' : 'light',
      prefersReducedData: window.matchMedia('(prefers-reduced-data: reduce)').matches
    };

    // Определяем уровень производительности устройства
    let performanceLevel = 'high'; // default

    if (capabilities.memory <= 2 || capabilities.cores <= 2) {
      performanceLevel = 'low';
    } else if (capabilities.memory <= 4 || capabilities.cores <= 4) {
      performanceLevel = 'medium';
    }

    // Если включён режим экономии данных — снижаем уровень
    if (capabilities.connection.saveData) {
      performanceLevel = 'low';
    }

    capabilities.performanceLevel = performanceLevel;

    console.log(`[Device] 📱 Capabilities:`, {
      memory: `${capabilities.memory}GB`,
      cores: capabilities.cores,
      connection: capabilities.connection.type,
      performanceLevel,
      standalone: capabilities.isStandalone
    });

    return capabilities;
  }

  // Экспортируем capabilities
  HEYS.device = getDeviceCapabilities();

  // Обновляем при изменении соединения
  if (navigator.connection) {
    navigator.connection.addEventListener('change', () => {
      HEYS.device = getDeviceCapabilities();
    });
  }

  // === Idle Detection API ===
  // Отслеживаем когда пользователь возвращается к устройству
  // Полезно для синхронизации данных и умных напоминаний
  let idleDetector = null;
  let lastIdleTime = null;

  async function startIdleDetection() {
    if (!('IdleDetector' in window)) {
      console.log('[Idle] IdleDetector API not supported');
      return false;
    }

    try {
      // Запрашиваем разрешение
      const state = await IdleDetector.requestPermission();
      if (state !== 'granted') {
        console.log('[Idle] Permission denied');
        return false;
      }

      idleDetector = new IdleDetector();

      idleDetector.addEventListener('change', () => {
        const { userState, screenState } = idleDetector;

        // Пользователь стал активен после простоя
        if (userState === 'active' && lastIdleTime) {
          const idleDuration = Date.now() - lastIdleTime;
          const idleMinutes = Math.round(idleDuration / 60000);

          console.log(`[Idle] 👋 User returned after ${idleMinutes} min`);

          // Если был неактивен больше 5 минут — синхронизируем данные
          if (idleMinutes >= 5 && window.HEYS?.cloud?.sync) {
            console.log('[Idle] Syncing after idle period...');
            window.HEYS.cloud.sync().catch(() => { });
          }

          // Если был неактивен больше 30 минут — проверяем обновления
          if (idleMinutes >= 30) {
            checkServerVersion(true);
          }

          // Dispatch custom event для компонентов
          window.dispatchEvent(new CustomEvent('heys:user-returned', {
            detail: { idleMinutes }
          }));

          lastIdleTime = null;
        }

        // Пользователь стал неактивен
        if (userState === 'idle' || screenState === 'locked') {
          lastIdleTime = Date.now();
          console.log('[Idle] 💤 User went idle/screen locked');
        }
      });

      // Порог простоя — 60 секунд
      await idleDetector.start({ threshold: 60000 });
      console.log('[Idle] ✅ Idle detection started');
      return true;

    } catch (e) {
      console.error('[Idle] Error starting detection:', e);
      return false;
    }
  }

  function stopIdleDetection() {
    if (idleDetector) {
      idleDetector.abort();
      idleDetector = null;
      console.log('[Idle] Stopped');
    }
  }

  // Экспортируем
  HEYS.idle = {
    start: startIdleDetection,
    stop: stopIdleDetection
  };

  // Автоматический запуск если в standalone режиме
  if (window.matchMedia('(display-mode: standalone)').matches) {
    setTimeout(startIdleDetection, 10000); // Запускаем через 10 сек после старта
  }

  // === Window Controls Overlay API ===
  // Для десктопных PWA — получаем информацию о области заголовка окна
  function initWindowControlsOverlay() {
    if (!('windowControlsOverlay' in navigator)) {
      console.log('[WCO] Window Controls Overlay not supported');
      return;
    }

    const overlay = navigator.windowControlsOverlay;

    // Получаем начальную геометрию
    function updateTitlebarGeometry() {
      const { visible, x, y, width, height } = overlay.getTitlebarAreaRect?.() || {};

      if (visible) {
        console.log(`[WCO] 📐 Titlebar area: ${width}x${height} at (${x}, ${y})`);

        // Устанавливаем CSS переменные для использования в стилях
        document.documentElement.style.setProperty('--titlebar-area-x', `${x}px`);
        document.documentElement.style.setProperty('--titlebar-area-y', `${y}px`);
        document.documentElement.style.setProperty('--titlebar-area-width', `${width}px`);
        document.documentElement.style.setProperty('--titlebar-area-height', `${height}px`);

        // Добавляем класс для стилизации
        document.body.classList.add('wco-enabled');
      } else {
        document.body.classList.remove('wco-enabled');
      }
    }

    // Слушаем изменения
    overlay.addEventListener('geometrychange', updateTitlebarGeometry);

    // Начальное обновление
    updateTitlebarGeometry();

    console.log('[WCO] ✅ Window Controls Overlay initialized');
  }

  // Инициализируем WCO если это десктоп PWA
  if (window.matchMedia('(display-mode: window-controls-overlay)').matches) {
    initWindowControlsOverlay();
  }

  // === Barcode Detection API ===
  // Сканирование штрих-кодов продуктов с камеры
  let barcodeDetector = null;

  async function initBarcodeDetector() {
    if (!('BarcodeDetector' in window)) {
      console.log('[Barcode] BarcodeDetector API not supported');
      return null;
    }

    try {
      // Получаем поддерживаемые форматы
      const formats = await BarcodeDetector.getSupportedFormats();
      console.log('[Barcode] Supported formats:', formats);

      // Создаём детектор для типичных продуктовых штрих-кодов
      const productFormats = formats.filter(f =>
        ['ean_13', 'ean_8', 'upc_a', 'upc_e', 'code_128', 'code_39'].includes(f)
      );

      if (productFormats.length === 0) {
        console.log('[Barcode] No product barcode formats supported');
        return null;
      }

      barcodeDetector = new BarcodeDetector({ formats: productFormats });
      console.log('[Barcode] ✅ Detector initialized with formats:', productFormats);
      return barcodeDetector;
    } catch (e) {
      console.error('[Barcode] Error initializing:', e);
      return null;
    }
  }

  // Сканирование из изображения
  async function scanBarcodeFromImage(imageSource) {
    if (!barcodeDetector) {
      await initBarcodeDetector();
    }

    if (!barcodeDetector) {
      return { success: false, error: 'BarcodeDetector not available' };
    }

    try {
      const barcodes = await barcodeDetector.detect(imageSource);

      if (barcodes.length > 0) {
        const barcode = barcodes[0];
        console.log('[Barcode] 📦 Detected:', barcode.rawValue, barcode.format);

        // Вибрация при успешном сканировании
        if (window.HEYS?.haptic) {
          HEYS.haptic.medium();
        }

        return {
          success: true,
          value: barcode.rawValue,
          format: barcode.format,
          bounds: barcode.boundingBox
        };
      }

      return { success: false, error: 'No barcode found' };
    } catch (e) {
      console.error('[Barcode] Scan error:', e);
      return { success: false, error: e.message };
    }
  }

  // Сканирование в реальном времени из видеопотока
  async function startBarcodeScanning(videoElement, onDetected) {
    if (!barcodeDetector) {
      await initBarcodeDetector();
    }

    if (!barcodeDetector) {
      return { success: false, error: 'BarcodeDetector not available' };
    }

    let scanning = true;
    let lastDetectedCode = null;
    let lastDetectedTime = 0;

    const scanFrame = async () => {
      if (!scanning || videoElement.paused || videoElement.ended) return;

      try {
        const barcodes = await barcodeDetector.detect(videoElement);

        if (barcodes.length > 0) {
          const barcode = barcodes[0];
          const now = Date.now();

          // Debounce — не срабатываем на один и тот же код чаще чем раз в 2 секунды
          if (barcode.rawValue !== lastDetectedCode || (now - lastDetectedTime) > 2000) {
            lastDetectedCode = barcode.rawValue;
            lastDetectedTime = now;

            console.log('[Barcode] 📦 Scanned:', barcode.rawValue);

            if (window.HEYS?.haptic) {
              HEYS.haptic.medium();
            }

            onDetected?.({
              value: barcode.rawValue,
              format: barcode.format,
              bounds: barcode.boundingBox
            });
          }
        }
      } catch (e) {
        // Игнорируем ошибки отдельных кадров
      }

      if (scanning) {
        requestAnimationFrame(scanFrame);
      }
    };

    requestAnimationFrame(scanFrame);

    return {
      success: true,
      stop: () => { scanning = false; }
    };
  }

  // Проверяем поддержку при старте
  initBarcodeDetector();

  // Экспортируем
  HEYS.barcode = {
    isSupported: () => 'BarcodeDetector' in window,
    scanImage: scanBarcodeFromImage,
    startScanning: startBarcodeScanning
  };

  // === Web Share API (исходящий) ===
  // Поделиться прогрессом, рецептами, результатами
  async function shareContent(data) {
    if (!navigator.share) {
      console.log('[Share] Web Share API not supported');
      // Fallback на clipboard
      if (navigator.clipboard && data.text) {
        await navigator.clipboard.writeText(data.text);
        HEYS.Toast?.success?.('Скопировано в буфер!');
        return { success: true, method: 'clipboard' };
      }
      return { success: false, error: 'Share not supported' };
    }

    try {
      await navigator.share(data);
      console.log('[Share] ✅ Shared successfully');

      if (window.HEYS?.haptic) {
        HEYS.haptic.light();
      }

      return { success: true, method: 'native' };
    } catch (e) {
      if (e.name === 'AbortError') {
        // Пользователь отменил — это нормально
        return { success: false, error: 'cancelled' };
      }
      console.error('[Share] Error:', e);
      return { success: false, error: e.message };
    }
  }

  // Проверяем возможность шаринга файлов
  function canShareFiles() {
    return navigator.canShare && navigator.canShare({ files: [new File([''], 'test.txt')] });
  }

  // Экспортируем
  HEYS.share = {
    isSupported: () => !!navigator.share,
    canShareFiles: canShareFiles,
    share: shareContent,

    // Удобные методы для типичных сценариев
    async shareProgress(stats) {
      const text = `🎯 Мой прогресс в HEYS:\n` +
        `📊 ${stats.streak || 0} дней подряд в норме\n` +
        `🔥 ${stats.kcal || 0} ккал сегодня\n` +
        `💧 ${stats.water || 0} мл воды\n\n` +
        `Попробуй HEYS: https://app.heyslab.ru`;

      return shareContent({ title: 'Мой прогресс в HEYS', text });
    },

    async shareDay(date, stats) {
      const text = `📅 ${date}\n` +
        `🔥 Калории: ${stats.kcal || 0}/${stats.norm || 0}\n` +
        `🥩 Белок: ${stats.protein || 0}г\n` +
        `💧 Вода: ${stats.water || 0} мл\n` +
        `👟 Шаги: ${stats.steps || 0}`;

      return shareContent({ title: `День ${date}`, text });
    }
  };

  // === Contact Picker API ===
  // Выбор контактов для приглашения друзей
  async function pickContacts(options = {}) {
    if (!('contacts' in navigator && 'ContactsManager' in window)) {
      console.log('[Contacts] Contact Picker API not supported');
      return { success: false, error: 'Not supported' };
    }

    try {
      const properties = options.properties || ['name', 'tel'];
      const opts = { multiple: options.multiple ?? true };

      const contacts = await navigator.contacts.select(properties, opts);

      if (contacts.length > 0) {
        console.log(`[Contacts] ✅ Selected ${contacts.length} contacts`);

        if (window.HEYS?.haptic) {
          HEYS.haptic.light();
        }

        return { success: true, contacts };
      }

      return { success: false, error: 'No contacts selected' };
    } catch (e) {
      if (e.name === 'InvalidStateError') {
        // Уже открыт picker — нормальная ситуация
        return { success: false, error: 'picker_busy' };
      }
      console.error('[Contacts] Error:', e);
      return { success: false, error: e.message };
    }
  }

  // Проверяем какие свойства контактов поддерживаются
  async function getSupportedContactProperties() {
    if (!('contacts' in navigator)) {
      return [];
    }

    try {
      return await navigator.contacts.getProperties();
    } catch (e) {
      return [];
    }
  }

  // Экспортируем
  HEYS.contacts = {
    isSupported: () => 'contacts' in navigator && 'ContactsManager' in window,
    pick: pickContacts,
    getSupportedProperties: getSupportedContactProperties
  };

  // === Speech Recognition API ===
  // Голосовой ввод продуктов
  let speechRecognition = null;

  function initSpeechRecognition() {
    const SpeechRecognition = window.SpeechRecognition || window.webkitSpeechRecognition;

    if (!SpeechRecognition) {
      console.log('[Speech] Speech Recognition not supported');
      return null;
    }

    const recognition = new SpeechRecognition();
    recognition.lang = 'ru-RU';
    recognition.continuous = false;
    recognition.interimResults = true;
    recognition.maxAlternatives = 3;

    return recognition;
  }

  // Распознать речь (Promise-based)
  function recognizeSpeech(options = {}) {
    return new Promise((resolve, reject) => {
      const recognition = initSpeechRecognition();

      if (!recognition) {
        reject(new Error('Speech recognition not supported'));
        return;
      }

      let finalTranscript = '';
      let interimCallback = options.onInterim;

      recognition.onresult = (event) => {
        let interim = '';

        for (let i = event.resultIndex; i < event.results.length; i++) {
          const result = event.results[i];

          if (result.isFinal) {
            finalTranscript += result[0].transcript;
          } else {
            interim += result[0].transcript;
          }
        }

        if (interimCallback && interim) {
          interimCallback(interim);
        }
      };

      recognition.onend = () => {
        if (finalTranscript) {
          console.log('[Speech] ✅ Recognized:', finalTranscript);

          if (window.HEYS?.haptic) {
            HEYS.haptic.light();
          }

          resolve({ success: true, text: finalTranscript.trim() });
        } else {
          resolve({ success: false, error: 'No speech detected' });
        }
      };

      recognition.onerror = (event) => {
        console.error('[Speech] Error:', event.error);
        reject(new Error(event.error));
      };

      try {
        recognition.start();
        console.log('[Speech] 🎤 Listening...');

        if (window.HEYS?.haptic) {
          HEYS.haptic.light();
        }
      } catch (e) {
        reject(e);
      }

      // Таймаут — останавливаем через N секунд
      const timeout = options.timeout || 10000;
      setTimeout(() => {
        try {
          recognition.stop();
        } catch (e) { }
      }, timeout);

      // Возвращаем способ остановить вручную
      speechRecognition = recognition;
    });
  }

  function stopSpeechRecognition() {
    if (speechRecognition) {
      try {
        speechRecognition.stop();
      } catch (e) { }
      speechRecognition = null;
    }
  }

  // Экспортируем
  HEYS.speech = {
    isSupported: () => !!(window.SpeechRecognition || window.webkitSpeechRecognition),
    recognize: recognizeSpeech,
    stop: stopSpeechRecognition
  };

  // === Launch Handler API ===
  // Обработка запуска приложения из разных источников
  if ('launchQueue' in window) {
    window.launchQueue.setConsumer((launchParams) => {
      console.log('[Launch] 🚀 App launched with params:', launchParams);

      // Если запущено с файлами (например, фото еды)
      if (launchParams.files?.length > 0) {
        console.log('[Launch] Files:', launchParams.files.map(f => f.name));

        // Сохраняем файлы для обработки
        window.HEYS_LAUNCH_FILES = launchParams.files;

        // Диспатчим событие для компонентов
        window.dispatchEvent(new CustomEvent('heys:launch-files', {
          detail: { files: launchParams.files }
        }));
      }

      // Если есть целевой URL
      if (launchParams.targetURL) {
        const url = new URL(launchParams.targetURL);
        console.log('[Launch] Target URL:', url.href);

        // Обрабатываем параметры URL
        const action = url.searchParams.get('action');
        const tab = url.searchParams.get('tab');

        if (action) {
          window.dispatchEvent(new CustomEvent('heys:url-action', {
            detail: { action }
          }));
        }

        if (tab) {
          window.dispatchEvent(new CustomEvent('heys:url-tab', {
            detail: { tab }
          }));
        }
      }
    });
    console.log('[Launch] ✅ Launch handler registered');
  }

  // === Protocol Handler ===
  // Регистрируем кастомный протокол web+heys://
  function registerProtocolHandler() {
    if (!navigator.registerProtocolHandler) {
      console.log('[Protocol] Protocol handler not supported');
      return false;
    }

    try {
      navigator.registerProtocolHandler(
        'web+heys',
        '/?protocol=%s',
        'HEYS Nutrition'
      );
      console.log('[Protocol] ✅ Registered web+heys:// protocol');
      return true;
    } catch (e) {
      console.error('[Protocol] Registration error:', e);
      return false;
    }
  }

  // Обработка protocol deep links
  function handleProtocolUrl() {
    const params = new URLSearchParams(window.location.search);
    const protocolUrl = params.get('protocol');

    if (protocolUrl) {
      console.log('[Protocol] Handling:', protocolUrl);

      // Парсим web+heys://action/params
      const match = protocolUrl.match(/^web\+heys:\/\/([^/]+)\/?(.*)$/);

      if (match) {
        const [, action, data] = match;

        window.dispatchEvent(new CustomEvent('heys:protocol-action', {
          detail: { action, data: decodeURIComponent(data) }
        }));

        // Очищаем URL от protocol параметра
        params.delete('protocol');
        const newUrl = params.toString()
          ? `${window.location.pathname}?${params.toString()}`
          : window.location.pathname;
        window.history.replaceState({}, '', newUrl);
      }
    }
  }

  // Вызываем обработку при старте
  handleProtocolUrl();

  // Экспортируем
  HEYS.protocol = {
    register: registerProtocolHandler,
    handleUrl: handleProtocolUrl
  };

  // === File System Access API ===
  // Для экспорта/импорта данных пользователя

  // Сохранить данные в файл
  async function saveToFile(data, filename = 'heys-export.json', type = 'application/json') {
    // Современный File System Access API
    if ('showSaveFilePicker' in window) {
      try {
        const handle = await window.showSaveFilePicker({
          suggestedName: filename,
          types: [{
            description: type === 'application/json' ? 'JSON файл' : 'Текстовый файл',
            accept: { [type]: [filename.split('.').pop() ? `.${filename.split('.').pop()}` : '.json'] }
          }]
        });

        const writable = await handle.createWritable();
        await writable.write(typeof data === 'string' ? data : JSON.stringify(data, null, 2));
        await writable.close();

        console.log('[FileSystem] ✅ Saved to:', handle.name);

        if (window.HEYS?.haptic) {
          HEYS.haptic.success();
        }

        return { success: true, filename: handle.name };
      } catch (e) {
        if (e.name === 'AbortError') {
          return { success: false, cancelled: true };
        }
        console.error('[FileSystem] Save error:', e);
      }
    }

    // Fallback: download link
    const blob = new Blob([typeof data === 'string' ? data : JSON.stringify(data, null, 2)], { type });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = filename;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);

    console.log('[FileSystem] 📥 Downloaded:', filename);
    return { success: true, filename, fallback: true };
  }

  // Открыть и прочитать файл
  async function openFile(accept = ['.json']) {
    // Современный File System Access API
    if ('showOpenFilePicker' in window) {
      try {
        const [handle] = await window.showOpenFilePicker({
          types: [{
            description: 'Файлы данных',
            accept: { 'application/*': accept }
          }],
          multiple: false
        });

        const file = await handle.getFile();
        const content = await file.text();

        console.log('[FileSystem] ✅ Opened:', file.name);

        return {
          success: true,
          filename: file.name,
          content,
          data: accept.includes('.json') ? JSON.parse(content) : content
        };
      } catch (e) {
        if (e.name === 'AbortError') {
          return { success: false, cancelled: true };
        }
        console.error('[FileSystem] Open error:', e);
      }
    }

    // Fallback: input file
    return new Promise((resolve) => {
      const input = document.createElement('input');
      input.type = 'file';
      input.accept = accept.join(',');

      input.onchange = async (e) => {
        const file = e.target.files?.[0];
        if (!file) {
          resolve({ success: false, cancelled: true });
          return;
        }

        const content = await file.text();
        resolve({
          success: true,
          filename: file.name,
          content,
          data: accept.includes('.json') ? JSON.parse(content) : content,
          fallback: true
        });
      };

      input.oncancel = () => resolve({ success: false, cancelled: true });
      input.click();
    });
  }

  // Экспорт всех данных пользователя
  async function exportUserData() {
    const data = {
      exportDate: new Date().toISOString(),
      appVersion: getAppVersion(),
      profile: HEYS.utils?.lsGet?.('heys_profile') || {},
      norms: HEYS.utils?.lsGet?.('heys_norms') || {},
      products: HEYS.products?.getAll?.() || [],
      // Последние 90 дней данных
      days: []
    };

    // Собираем данные за 90 дней
    const today = new Date();
    for (let i = 0; i < 90; i++) {
      const date = new Date(today);
      date.setDate(date.getDate() - i);
      const dateStr = date.toISOString().split('T')[0];
      const dayData = HEYS.utils?.lsGet?.(`heys_dayv2_${dateStr}`);
      if (dayData) {
        data.days.push({ date: dateStr, ...dayData });
      }
    }

    const filename = `heys-export-${today.toISOString().split('T')[0]}.json`;
    return saveToFile(data, filename);
  }

  // Импорт данных пользователя
  async function importUserData() {
    const result = await openFile(['.json']);

    if (!result.success || result.cancelled) {
      return result;
    }

    const data = result.data;

    // Валидация
    if (!data.appVersion || !data.exportDate) {
      return { success: false, error: 'Invalid export file' };
    }

    // Импортируем данные
    let imported = { profile: false, norms: false, products: 0, days: 0 };

    if (data.profile && HEYS.utils?.lsSet) {
      HEYS.utils.lsSet('heys_profile', data.profile);
      imported.profile = true;
    }

    if (data.norms && HEYS.utils?.lsSet) {
      HEYS.utils.lsSet('heys_norms', data.norms);
      imported.norms = true;
    }

    if (data.products?.length && HEYS.products?.setAll) {
      const existing = HEYS.products.getAll() || [];
      const merged = [...existing];

      for (const product of data.products) {
        if (!merged.find(p => p.id === product.id)) {
          merged.push(product);
          imported.products++;
        }
      }

      HEYS.products.setAll(merged, { source: 'import-user-data' });
    }

    if (data.days?.length && HEYS.utils?.lsSet) {
      for (const day of data.days) {
        const key = `heys_dayv2_${day.date}`;
        const existing = HEYS.utils.lsGet(key);

        // Не перезаписываем существующие данные
        if (!existing) {
          HEYS.utils.lsSet(key, day);
          imported.days++;
        }
      }
    }

    console.log('[FileSystem] ✅ Imported:', imported);

    if (window.HEYS?.haptic) {
      HEYS.haptic.success();
    }

    return { success: true, imported, fromFile: result.filename };
  }

  HEYS.fileSystem = {
    isSupported: () => 'showSaveFilePicker' in window,
    saveToFile,
    openFile,
    exportUserData,
    importUserData
  };

  // === Credential Management API ===
  // Безопасное хранение учётных данных

  async function saveCredentials(phone, pin, name = 'HEYS Nutrition') {
    if (!('credentials' in navigator) || !window.PasswordCredential) {
      console.log('[Credentials] API not supported');
      return { success: false, reason: 'not_supported' };
    }

    try {
      const credential = new PasswordCredential({
        id: phone,
        password: pin,
        name: name
      });

      await navigator.credentials.store(credential);
      console.log('[Credentials] ✅ Saved credentials');
      return { success: true };
    } catch (e) {
      console.error('[Credentials] Save error:', e);
      return { success: false, error: e.message };
    }
  }

  async function getCredentials() {
    if (!('credentials' in navigator)) {
      return { success: false, reason: 'not_supported' };
    }

    try {
      const credential = await navigator.credentials.get({
        password: true,
        mediation: 'optional'
      });

      if (credential) {
        console.log('[Credentials] ✅ Retrieved credentials for:', credential.id);
        return {
          success: true,
          phone: credential.id,
          pin: credential.password,
          name: credential.name
        };
      }

      return { success: false, reason: 'no_credentials' };
    } catch (e) {
      console.error('[Credentials] Get error:', e);
      return { success: false, error: e.message };
    }
  }

  async function clearCredentials() {
    if (!('credentials' in navigator)) {
      return { success: false, reason: 'not_supported' };
    }

    try {
      await navigator.credentials.preventSilentAccess();
      console.log('[Credentials] ✅ Cleared silent access');
      return { success: true };
    } catch (e) {
      console.error('[Credentials] Clear error:', e);
      return { success: false, error: e.message };
    }
  }

  HEYS.credentials = {
    isSupported: () => 'credentials' in navigator && !!window.PasswordCredential,
    save: saveCredentials,
    get: getCredentials,
    clear: clearCredentials
  };

  // === Screen Orientation API ===
  // Управление ориентацией экрана

  async function lockOrientation(orientation = 'portrait') {
    if (!screen.orientation?.lock) {
      console.log('[Orientation] Lock not supported');
      return { success: false, reason: 'not_supported' };
    }

    try {
      await screen.orientation.lock(orientation);
      console.log('[Orientation] ✅ Locked to:', orientation);
      return { success: true, orientation };
    } catch (e) {
      console.error('[Orientation] Lock error:', e);
      return { success: false, error: e.message };
    }
  }

  function unlockOrientation() {
    if (!screen.orientation?.unlock) {
      return { success: false, reason: 'not_supported' };
    }

    screen.orientation.unlock();
    console.log('[Orientation] ✅ Unlocked');
    return { success: true };
  }

  HEYS.orientation = {
    isSupported: () => !!screen.orientation?.lock,
    lock: lockOrientation,
    unlock: unlockOrientation,
    get current() { return screen.orientation?.type || 'unknown'; },
    get angle() { return screen.orientation?.angle || 0; },
    onChange: (callback) => {
      screen.orientation?.addEventListener('change', callback);
      return () => screen.orientation?.removeEventListener('change', callback);
    }
  };

  // === Fullscreen API ===
  // Управление полноэкранным режимом

  async function enterFullscreen(element = document.documentElement) {
    try {
      if (element.requestFullscreen) {
        await element.requestFullscreen();
      } else if (element.webkitRequestFullscreen) {
        await element.webkitRequestFullscreen();
      } else if (element.msRequestFullscreen) {
        await element.msRequestFullscreen();
      } else {
        return { success: false, reason: 'not_supported' };
      }

      console.log('[Fullscreen] ✅ Entered fullscreen');

      if (window.HEYS?.haptic) {
        HEYS.haptic.light();
      }

      return { success: true };
    } catch (e) {
      console.error('[Fullscreen] Enter error:', e);
      return { success: false, error: e.message };
    }
  }

  async function exitFullscreen() {
    try {
      if (document.exitFullscreen) {
        await document.exitFullscreen();
      } else if (document.webkitExitFullscreen) {
        await document.webkitExitFullscreen();
      } else if (document.msExitFullscreen) {
        await document.msExitFullscreen();
      } else {
        return { success: false, reason: 'not_supported' };
      }

      console.log('[Fullscreen] ✅ Exited fullscreen');
      return { success: true };
    } catch (e) {
      console.error('[Fullscreen] Exit error:', e);
      return { success: false, error: e.message };
    }
  }

  function isFullscreen() {
    return !!(
      document.fullscreenElement ||
      document.webkitFullscreenElement ||
      document.msFullscreenElement
    );
  }

  HEYS.fullscreen = {
    isSupported: () => !!(document.documentElement.requestFullscreen || document.documentElement.webkitRequestFullscreen),
    enter: enterFullscreen,
    exit: exitFullscreen,
    toggle: async (element) => isFullscreen() ? exitFullscreen() : enterFullscreen(element),
    get isActive() { return isFullscreen(); },
    onChange: (callback) => {
      const events = ['fullscreenchange', 'webkitfullscreenchange', 'msfullscreenchange'];
      events.forEach(e => document.addEventListener(e, callback));
      return () => events.forEach(e => document.removeEventListener(e, callback));
    }
  };

  // === Vibration Pattern API ===
  // Расширенные паттерны вибрации

  const VIBRATION_PATTERNS = {
    success: [50, 30, 50],           // Короткий двойной
    error: [100, 50, 100, 50, 100],  // Тройной
    warning: [200, 100, 200],        // Двойной длинный
    notification: [50, 100, 50, 100, 50], // Быстрая серия
    heartbeat: [100, 200, 100, 400], // Как сердцебиение
    sos: [100, 50, 100, 50, 100, 200, 300, 50, 300, 50, 300, 200, 100, 50, 100, 50, 100], // SOS
    countdown: [100, 800, 100, 800, 100, 800, 500], // Обратный отсчёт
    levelUp: [50, 50, 50, 50, 50, 50, 200] // Нарастающий
  };

  function vibratePattern(pattern) {
    if (!navigator.vibrate) {
      return false;
    }

    const p = typeof pattern === 'string' ? VIBRATION_PATTERNS[pattern] : pattern;

    if (!p) {
      console.warn('[Vibration] Unknown pattern:', pattern);
      return false;
    }

    navigator.vibrate(p);
    return true;
  }

  HEYS.vibration = {
    isSupported: () => 'vibrate' in navigator,
    patterns: VIBRATION_PATTERNS,
    play: vibratePattern,
    stop: () => navigator.vibrate?.(0),
    // Удобные методы
    success: () => vibratePattern('success'),
    error: () => vibratePattern('error'),
    warning: () => vibratePattern('warning'),
    notification: () => vibratePattern('notification'),
    heartbeat: () => vibratePattern('heartbeat'),
    levelUp: () => vibratePattern('levelUp')
  };

  // === Web Animations API utilities ===
  // Утилиты для анимаций

  function animateElement(element, keyframes, options = {}) {
    if (!element?.animate) {
      return null;
    }

    const defaultOptions = {
      duration: 300,
      easing: 'ease-out',
      fill: 'forwards'
    };

    return element.animate(keyframes, { ...defaultOptions, ...options });
  }

  // Готовые анимации
  const ANIMATIONS = {
    fadeIn: [
      { opacity: 0 },
      { opacity: 1 }
    ],
    fadeOut: [
      { opacity: 1 },
      { opacity: 0 }
    ],
    slideUp: [
      { transform: 'translateY(100%)', opacity: 0 },
      { transform: 'translateY(0)', opacity: 1 }
    ],
    slideDown: [
      { transform: 'translateY(-100%)', opacity: 0 },
      { transform: 'translateY(0)', opacity: 1 }
    ],
    scaleIn: [
      { transform: 'scale(0.8)', opacity: 0 },
      { transform: 'scale(1)', opacity: 1 }
    ],
    scaleOut: [
      { transform: 'scale(1)', opacity: 1 },
      { transform: 'scale(0.8)', opacity: 0 }
    ],
    shake: [
      { transform: 'translateX(0)' },
      { transform: 'translateX(-10px)' },
      { transform: 'translateX(10px)' },
      { transform: 'translateX(-10px)' },
      { transform: 'translateX(10px)' },
      { transform: 'translateX(0)' }
    ],
    pulse: [
      { transform: 'scale(1)' },
      { transform: 'scale(1.05)' },
      { transform: 'scale(1)' }
    ],
    bounce: [
      { transform: 'translateY(0)' },
      { transform: 'translateY(-20px)' },
      { transform: 'translateY(0)' },
      { transform: 'translateY(-10px)' },
      { transform: 'translateY(0)' }
    ],
    spin: [
      { transform: 'rotate(0deg)' },
      { transform: 'rotate(360deg)' }
    ],
    confetti: [
      { transform: 'translateY(0) rotate(0deg)', opacity: 1 },
      { transform: 'translateY(-200px) rotate(720deg)', opacity: 0 }
    ]
  };

  HEYS.animate = {
    isSupported: () => !!document.documentElement.animate,
    element: animateElement,
    presets: ANIMATIONS,
    fadeIn: (el, opts) => animateElement(el, ANIMATIONS.fadeIn, opts),
    fadeOut: (el, opts) => animateElement(el, ANIMATIONS.fadeOut, opts),
    slideUp: (el, opts) => animateElement(el, ANIMATIONS.slideUp, opts),
    slideDown: (el, opts) => animateElement(el, ANIMATIONS.slideDown, opts),
    scaleIn: (el, opts) => animateElement(el, ANIMATIONS.scaleIn, opts),
    scaleOut: (el, opts) => animateElement(el, ANIMATIONS.scaleOut, opts),
    shake: (el, opts = { duration: 500 }) => animateElement(el, ANIMATIONS.shake, opts),
    pulse: (el, opts = { duration: 400, iterations: 2 }) => animateElement(el, ANIMATIONS.pulse, opts),
    bounce: (el, opts = { duration: 600 }) => animateElement(el, ANIMATIONS.bounce, opts),
    spin: (el, opts = { duration: 500 }) => animateElement(el, ANIMATIONS.spin, opts)
  };

  // ============================================================================
  // MODULE EXPORTS
  // ============================================================================

  // Экспортируем все Platform APIs в namespace
  HEYS.PlatformAPIs = {
    // Service Worker
    registerServiceWorker: registerServiceWorker,
    triggerSkipWaiting: triggerSkipWaiting,
    forceUpdateAndReload: forceUpdateAndReload,

    // Update helpers
    getAppVersion: getAppVersion,
    isNewerVersion: isNewerVersion,
    isUpdateLocked: isUpdateLocked,
    setUpdateLock: setUpdateLock,
    clearUpdateLock: clearUpdateLock,
    showUpdateBadge: showUpdateBadge,
    hideUpdateBadge: hideUpdateBadge,
    showUpdateModal: showUpdateModal,
    updateModalStage: updateModalStage,
    hideUpdateModal: hideUpdateModal,
    showManualRefreshPrompt: showManualRefreshPrompt,
    installUpdate: installUpdate,
    getNetworkQuality: getNetworkQuality,
    smartVersionCheck: smartVersionCheck,
    checkServerVersion: checkServerVersion,
    getUpdateState: () => ({ available: _updateAvailable, version: _updateVersion }),

    // Storage
    storage: {
      requestPersistent: requestPersistentStorage,
      getEstimate: getStorageEstimate
    },

    // Уже экспортированные API доступны через HEYS.*
    // (device, idle, barcode, share, contacts, speech, etc.)
  };

  // Performance tracking end
  HEYS.modulePerf?.endLoad('platform_apis', true);

  // Backward compatibility globals
  window.isUpdateLocked = window.isUpdateLocked || isUpdateLocked;
  window.setUpdateLock = window.setUpdateLock || setUpdateLock;
  window.clearUpdateLock = window.clearUpdateLock || clearUpdateLock;
  window.showUpdateBadge = window.showUpdateBadge || showUpdateBadge;
  window.hideUpdateModal = window.hideUpdateModal || hideUpdateModal;
  window.showUpdateModal = window.showUpdateModal || showUpdateModal;
  window.updateModalStage = window.updateModalStage || updateModalStage;
  window.getNetworkQuality = window.getNetworkQuality || getNetworkQuality;
  window.showManualRefreshPrompt = window.showManualRefreshPrompt || showManualRefreshPrompt;
  window.checkServerVersion = window.checkServerVersion || checkServerVersion;

  // 🚀 Auto-register Service Worker on module load
  // This was previously called from runVersionGuard() in heys_app_v12.js
  registerServiceWorker();

  if (HEYS.featureFlags?.isEnabled('dev_module_logging')) {
    console.log('[PlatformAPIs] ✅ Module loaded successfully');
  }
})();


/* ===== heys_audio_v1.js ===== */
/**
 * HEYS Unified Audio Module v1
 * Единый движок звука и вибрации для всего приложения.
 *
 * API:
 *   HEYS.audio.play(eventOrCategory)  — воспроизвести звук + вибрацию по событию
 *   HEYS.audio.haptic(pattern)        — только вибрация (массив ms)
 *   HEYS.audio.preview(category)      — превью звука для настроек (игнорирует тихие часы)
 *   HEYS.audio.getSettings()          — текущие настройки
 *   HEYS.audio.saveSettings(updates)  — сохранить настройки (перезаписывает частично)
 *   HEYS.audio.isEnabled()            — true если masterEnabled
 *   HEYS.audio.EVENTS                 — карта всех событий → категории (freeze)
 *   HEYS.audio.CATEGORIES             — список категорий (freeze)
 *
 * Kill switch: localStorage.setItem('heys_audio_disabled', 'true')
 *
 * @file heys_audio_v1.js
 * @version 1.0.0
 */
(function (global) {
  'use strict';

  const HEYS = global.HEYS = global.HEYS || {};

  // ─── Kill switch ──────────────────────────────────────────────────────────
  if (localStorage.getItem('heys_audio_disabled') === 'true') {
    HEYS.audio = {
      play: () => {},
      haptic: () => {},
      preview: () => {},
      isEnabled: () => false,
      getSettings: () => ({ masterEnabled: false }),
      saveSettings: () => {},
      invalidateSettings: () => {},
      EVENTS: Object.freeze({}),
      CATEGORIES: Object.freeze([])
    };
    console.info('[HEYS.audio] ⚠️ Disabled via kill switch');
    return;
  }

  // ─── Defaults ─────────────────────────────────────────────────────────────
  const DEFAULT_SETTINGS = {
    masterEnabled: true,
    volume: 0.12,
    hapticEnabled: true,
    quietHoursEnabled: true,
    quietStart: 23,
    quietEnd: 7
  };

  const SETTINGS_KEY = 'heys_audio_settings';

  function hasOwn(obj, key) {
    return Object.prototype.hasOwnProperty.call(obj, key);
  }

  // ─── Settings ─────────────────────────────────────────────────────────────
  let _settings = null;

  function _lsGet(key, fallback) {
    try {
      const fn = HEYS.utils?.lsGet;
      if (fn) return fn(key, fallback);
      const raw = localStorage.getItem(key);
      if (raw == null) return fallback;
      return JSON.parse(raw);
    } catch { return fallback; }
  }

  function _lsSet(key, value) {
    try {
      const fn = HEYS.utils?.lsSet;
      if (fn) { fn(key, value); return; }
      localStorage.setItem(key, JSON.stringify(value));
    } catch { /* ignore */ }
  }

  function loadSettings() {
    if (_settings) return _settings;

    const raw = _lsGet(SETTINGS_KEY, null);
    if (raw && typeof raw === 'object') {
      _settings = Object.assign({}, DEFAULT_SETTINGS, raw);
      if (hasOwn(_settings, 'enabled') && !hasOwn(_settings, 'masterEnabled')) {
        _settings.masterEnabled = _settings.enabled !== false;
      }
      return _settings;
    }

    // First launch — migrate from legacy keys
    _settings = Object.assign({}, DEFAULT_SETTINGS);

    try {
      // heys_sound_enabled (heys_day_sound_v1)
      const soundEnabled = _lsGet('heys_sound_enabled', null);
      if (soundEnabled === false) _settings.masterEnabled = false;

      // heys_sound_settings (heys_gamification_v1)
      const soundSettings = _lsGet('heys_sound_settings', null);
      if (soundSettings) {
        if (soundSettings.enabled === false) _settings.masterEnabled = false;
        if (typeof soundSettings.volume === 'number') _settings.volume = soundSettings.volume;
      }

      // heys_advice_settings.soundEnabled (heys_sounds_v1)
      const adviceSettings = _lsGet('heys_advice_settings', null);
      if (adviceSettings?.soundEnabled === false) _settings.masterEnabled = false;
    } catch { /* ignore */ }

    return _settings;
  }

  function invalidateSettings() {
    _settings = null;
  }

  function saveSettings(updates) {
    const s = loadSettings();
    const normalizedUpdates = Object.assign({}, updates);
    if (hasOwn(normalizedUpdates, 'enabled') && !hasOwn(normalizedUpdates, 'masterEnabled')) {
      normalizedUpdates.masterEnabled = normalizedUpdates.enabled !== false;
      delete normalizedUpdates.enabled;
    }
    if (hasOwn(normalizedUpdates, 'soundEnabled') && !hasOwn(normalizedUpdates, 'masterEnabled')) {
      normalizedUpdates.masterEnabled = normalizedUpdates.soundEnabled !== false;
      delete normalizedUpdates.soundEnabled;
    }
    Object.assign(s, normalizedUpdates);
    _lsSet(SETTINGS_KEY, s);
    invalidateSettings();
  }

  // ─── Time checks ──────────────────────────────────────────────────────────
  function isQuietHours() {
    const s = loadSettings();
    if (!s.quietHoursEnabled) return false;
    const hour = new Date().getHours();
    const start = s.quietStart;
    const end = s.quietEnd;
    // Handles midnight wrap: e.g. 23-07
    if (start > end) return hour >= start || hour < end;
    return hour >= start && hour < end;
  }

  function prefersReducedMotion() {
    try {
      return window.matchMedia('(prefers-reduced-motion: reduce)').matches;
    } catch { return false; }
  }

  function prefersReducedTransparency() {
    try {
      return window.matchMedia('(prefers-reduced-transparency: reduce)').matches;
    } catch { return false; }
  }

  function isDocumentHidden() {
    try {
      return typeof document !== 'undefined' && document.visibilityState === 'hidden';
    } catch {
      return false;
    }
  }

  // ─── AudioContext (lazy, user-gesture-aware) ──────────────────────────────
  let _audioCtx = null;
  let _userGestured = false;

  function _markUserGesture() {
    _userGestured = true;
  }

  document.addEventListener('click', _markUserGesture, { once: true, passive: true });
  document.addEventListener('touchstart', _markUserGesture, { once: true, passive: true });
  document.addEventListener('keydown', _markUserGesture, { once: true, passive: true });

  function getCtx() {
    if (!_userGestured) return null;
    if (!_audioCtx) {
      const AudioContext = window.AudioContext || window.webkitAudioContext;
      if (!AudioContext) return null;
      try { _audioCtx = new AudioContext(); } catch { return null; }
    }
    if (_audioCtx.state === 'closed') {
      // Context was closed — create a new one
      const AudioContext = window.AudioContext || window.webkitAudioContext;
      try { _audioCtx = new AudioContext(); } catch { return null; }
    }
    if (_audioCtx.state === 'suspended') {
      _audioCtx.resume().catch(() => {});
    }
    return _audioCtx;
  }

  if (typeof document !== 'undefined') {
    document.addEventListener('visibilitychange', () => {
      if (!_audioCtx) return;
      if (document.visibilityState === 'hidden') {
        _audioCtx.suspend?.().catch(() => {});
        return;
      }
      if (document.visibilityState === 'visible' && _userGestured) {
        _audioCtx.resume?.().catch(() => {});
      }
    });
  }

  // ─── Haptic ────────────────────────────────────────────────────────────────
  function triggerHaptic(pattern) {
    try {
      if (HEYS.vibration?.play) {
        HEYS.vibration.play(pattern);
        return;
      }
      if (navigator.vibrate) {
        navigator.vibrate(pattern);
      }
    } catch { /* ignore */ }
  }

  // ─── Deduplication / cooldown ─────────────────────────────────────────────
  const _lastPlayTime = {};

  // Per-category minimum interval between plays (ms)
  const COOLDOWN = {
    triumph: 3000,
    success: 1500,
    reward: 500,
    notify: 800,
    caution: 800,
    alert: 2000,
    error: 1000,
    interaction: 100,
    dismiss: 400
  };

  function isThrottled(category) {
    const now = Date.now();
    const last = _lastPlayTime[category] || 0;
    if (now - last < (COOLDOWN[category] || 800)) return true;
    _lastPlayTime[category] = now;
    return false;
  }

  // ─── Sound synthesis functions ────────────────────────────────────────────
  // Each takes (ctx, vol) and synthesizes a sound using Web Audio API.

  function synthTriumph(ctx, vol) {
    // Epic ascending arpeggio: G4 → C5 → E5 → G5 → C6 → E6
    const notes = [392.0, 523.25, 659.25, 783.99, 1046.5, 1318.5];
    const stagger = 0.08;
    notes.forEach((freq, i) => {
      const osc = ctx.createOscillator();
      const gain = ctx.createGain();
      osc.connect(gain);
      gain.connect(ctx.destination);
      osc.type = i < 3 ? 'sine' : 'triangle';
      osc.frequency.value = freq;
      const t = ctx.currentTime + i * stagger;
      gain.gain.setValueAtTime(0, t);
      gain.gain.linearRampToValueAtTime(vol * (1.0 - i * 0.03), t + 0.02);
      gain.gain.exponentialRampToValueAtTime(0.001, t + 0.5);
      osc.start(t);
      osc.stop(t + 0.55);
    });
  }

  function synthSuccess(ctx, vol) {
    // Warm 3-note stagger: E5 + A5 + D6
    const notes = [659.25, 880.0, 1174.66];
    notes.forEach((freq, i) => {
      const osc = ctx.createOscillator();
      const gain = ctx.createGain();
      osc.connect(gain);
      gain.connect(ctx.destination);
      osc.type = 'sine';
      osc.frequency.value = freq;
      const t = ctx.currentTime + i * 0.06;
      gain.gain.setValueAtTime(0, t);
      gain.gain.linearRampToValueAtTime(vol * (0.9 - i * 0.1), t + 0.02);
      gain.gain.exponentialRampToValueAtTime(0.001, t + 0.38);
      osc.start(t);
      osc.stop(t + 0.42);
    });
  }

  function synthReward(ctx, vol) {
    // Quick sparkle: A5 + D6
    const notes = [880.0, 1174.66];
    notes.forEach((freq, i) => {
      const osc = ctx.createOscillator();
      const gain = ctx.createGain();
      osc.connect(gain);
      gain.connect(ctx.destination);
      osc.type = 'sine';
      osc.frequency.value = freq;
      const t = ctx.currentTime + i * 0.04;
      gain.gain.setValueAtTime(0, t);
      gain.gain.linearRampToValueAtTime(vol * (0.7 - i * 0.15), t + 0.01);
      gain.gain.exponentialRampToValueAtTime(0.001, t + 0.18);
      osc.start(t);
      osc.stop(t + 0.22);
    });
  }

  function synthNotify(ctx, vol) {
    // Soft chime: F5 + C6
    const notes = [698.46, 1046.5];
    notes.forEach((freq, i) => {
      const osc = ctx.createOscillator();
      const gain = ctx.createGain();
      osc.connect(gain);
      gain.connect(ctx.destination);
      osc.type = 'sine';
      osc.frequency.value = freq;
      const t = ctx.currentTime + i * 0.07;
      gain.gain.setValueAtTime(0, t);
      gain.gain.linearRampToValueAtTime(vol * 0.5, t + 0.02);
      gain.gain.exponentialRampToValueAtTime(0.001, t + 0.22);
      osc.start(t);
      osc.stop(t + 0.27);
    });
  }

  function synthCaution(ctx, vol) {
    // Descending minor: E5 → D5, triangle wave
    const osc = ctx.createOscillator();
    const gain = ctx.createGain();
    osc.connect(gain);
    gain.connect(ctx.destination);
    osc.type = 'triangle';
    osc.frequency.setValueAtTime(659.25, ctx.currentTime);       // E5
    osc.frequency.setValueAtTime(587.33, ctx.currentTime + 0.1); // D5
    gain.gain.setValueAtTime(0, ctx.currentTime);
    gain.gain.linearRampToValueAtTime(vol * 0.8, ctx.currentTime + 0.025);
    gain.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + 0.3);
    osc.start(ctx.currentTime);
    osc.stop(ctx.currentTime + 0.35);
  }

  function synthAlert(ctx, vol) {
    // Tritone: F#4 + C5 — dissonant, attention-grabbing
    const freqs = [369.99, 523.25];
    freqs.forEach((freq, i) => {
      const osc = ctx.createOscillator();
      const gain = ctx.createGain();
      osc.connect(gain);
      gain.connect(ctx.destination);
      osc.type = i === 0 ? 'sawtooth' : 'triangle';
      osc.frequency.value = freq;
      gain.gain.setValueAtTime(0, ctx.currentTime);
      gain.gain.linearRampToValueAtTime(vol * (i === 0 ? 0.9 : 0.7), ctx.currentTime + 0.025);
      gain.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + 0.32);
      osc.start(ctx.currentTime);
      osc.stop(ctx.currentTime + 0.38);
    });
  }

  function synthError(ctx, vol) {
    // Heavy descending: A3 → G3
    const osc = ctx.createOscillator();
    const gain = ctx.createGain();
    osc.connect(gain);
    gain.connect(ctx.destination);
    osc.type = 'sawtooth';
    osc.frequency.setValueAtTime(220, ctx.currentTime);       // A3
    osc.frequency.setValueAtTime(196, ctx.currentTime + 0.12); // G3
    gain.gain.setValueAtTime(0, ctx.currentTime);
    gain.gain.linearRampToValueAtTime(vol, ctx.currentTime + 0.03);
    gain.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + 0.38);
    osc.start(ctx.currentTime);
    osc.stop(ctx.currentTime + 0.42);
  }

  function synthInteraction(ctx, vol) {
    // Subtle tap: 800 → 600 Hz, 60ms
    const osc = ctx.createOscillator();
    const gain = ctx.createGain();
    osc.connect(gain);
    gain.connect(ctx.destination);
    osc.type = 'sine';
    osc.frequency.setValueAtTime(800, ctx.currentTime);
    osc.frequency.exponentialRampToValueAtTime(600, ctx.currentTime + 0.06);
    gain.gain.setValueAtTime(vol * 0.22, ctx.currentTime);
    gain.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + 0.065);
    osc.start(ctx.currentTime);
    osc.stop(ctx.currentTime + 0.07);
  }

  function synthDismiss(ctx, vol) {
    // Filtered sawtooth whoosh: 200 → 50 Hz
    const osc = ctx.createOscillator();
    const filter = ctx.createBiquadFilter();
    const gain = ctx.createGain();
    osc.connect(filter);
    filter.connect(gain);
    gain.connect(ctx.destination);
    osc.type = 'sawtooth';
    osc.frequency.setValueAtTime(200, ctx.currentTime);
    osc.frequency.exponentialRampToValueAtTime(50, ctx.currentTime + 0.15);
    filter.type = 'lowpass';
    filter.frequency.setValueAtTime(2000, ctx.currentTime);
    filter.frequency.exponentialRampToValueAtTime(200, ctx.currentTime + 0.15);
    gain.gain.setValueAtTime(vol * 0.5, ctx.currentTime);
    gain.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + 0.17);
    osc.start(ctx.currentTime);
    osc.stop(ctx.currentTime + 0.2);
  }

  // ─── Category registry ────────────────────────────────────────────────────
  const SYNTH = {
    triumph: synthTriumph,
    success: synthSuccess,
    reward: synthReward,
    notify: synthNotify,
    caution: synthCaution,
    alert: synthAlert,
    error: synthError,
    interaction: synthInteraction,
    dismiss: synthDismiss
  };

  // Haptic pattern per category
  const HAPTIC_PATTERN = {
    triumph:     [50, 50, 50, 50, 50, 50, 200],
    success:     [50, 30, 50],
    reward:      [20],
    notify:      [15],
    caution:     [40, 20, 40],
    alert:       [200, 100, 200],
    error:       [100, 50, 100, 50, 100],
    interaction: [5],
    dismiss:     [15]
  };

  // ─── Event → category map ─────────────────────────────────────────────────
  // null = haptic-only, no sound
  const EVENT_MAP = {
    // Triumph
    rankCeremony:        'triumph',
    levelUp:             'triumph',
    allMissionsComplete: 'triumph',
    achievementUnlocked: 'triumph',

    // Success
    missionComplete:     'success',
    calorieGoalReached:  'success',
    supplementsComplete: 'success',

    // Reward
    xpGained:            'reward',
    foodAdded:           'reward',

    // Notify
    adviceAppear:        'notify',

    // Caution
    foodAddedModerate:   'caution',

    // Alert
    foodAddedHarmful:    'alert',

    // Error
    error:               'error',

    // Interaction
    buttonTap:           'interaction',

    // Dismiss
    adviceDismiss:       'dismiss',

    // Water: haptic-only (too frequent for sound)
    waterAdded:          null
  };

  function toPublicSettings(settings) {
    return {
      masterEnabled: settings.masterEnabled !== false,
      enabled: settings.masterEnabled !== false,
      volume: settings.volume,
      hapticEnabled: settings.hapticEnabled !== false,
      quietHoursEnabled: settings.quietHoursEnabled !== false,
      quietStart: settings.quietStart,
      quietEnd: settings.quietEnd
    };
  }

  function canPlay(eventOrCategory, options) {
    const s = loadSettings();
    if (!s.masterEnabled) return false;

    const cat = hasOwn(EVENT_MAP, eventOrCategory)
      ? EVENT_MAP[eventOrCategory]
      : eventOrCategory;

    if (cat === null) {
      return s.hapticEnabled && !prefersReducedMotion() && !isDocumentHidden();
    }

    if (!cat || !SYNTH[cat]) return false;
    if (isDocumentHidden() && options?.allowInBackground !== true) return false;
    if (isQuietHours() && options?.ignoreQuietHours !== true) return false;
    if (prefersReducedTransparency() && cat === 'interaction') return false;
    return !prefersReducedMotion();
  }

  // ─── Core play ────────────────────────────────────────────────────────────
  function play(eventOrCategory, options) {
    const s = loadSettings();
    if (!s.masterEnabled) return;

    const cat = hasOwn(EVENT_MAP, eventOrCategory)
      ? EVENT_MAP[eventOrCategory]
      : eventOrCategory;

    const hidden = isDocumentHidden();
    if (hidden && options?.allowInBackground !== true) {
      console.info('[HEYS.audio] ⏸ skipped in hidden tab:', eventOrCategory);
      return;
    }

    // null category = haptic-only event
    if (cat === null) {
      if (s.hapticEnabled && !prefersReducedMotion()) triggerHaptic([20]);
      return;
    }

    if (!cat || !SYNTH[cat]) {
      console.warn('[HEYS.audio] Unknown event/category:', eventOrCategory);
      return;
    }

    if (isThrottled(cat)) return;

    // Haptic — never muted by quiet hours
    const doHaptic = options?.haptic !== false;
    if (doHaptic && s.hapticEnabled && !prefersReducedMotion()) {
      triggerHaptic(HAPTIC_PATTERN[cat] || [20]);
    }

    // Sound — muted in quiet hours and when prefers-reduced-motion
    if ((!isQuietHours() || options?.ignoreQuietHours === true) && !prefersReducedMotion()) {
      const ctx = getCtx();
      if (ctx) {
        const vol = typeof options?.volume === 'number' ? options.volume : s.volume;
        try {
          SYNTH[cat](ctx, vol);
        } catch (e) {
          console.warn('[HEYS.audio] Synthesis error:', cat, e);
        }
      }
    }

    console.info('[HEYS.audio] ▶ play:', eventOrCategory, '->', cat);
  }

  // ─── Haptic-only helper ───────────────────────────────────────────────────
  function haptic(pattern) {
    const s = loadSettings();
    if (!s.masterEnabled || !s.hapticEnabled || prefersReducedMotion() || isDocumentHidden()) return;
    triggerHaptic(Array.isArray(pattern) ? pattern : [pattern]);
  }

  // ─── Preview (for settings UI, skips quiet hours) ─────────────────────────
  function preview(category) {
    const s = loadSettings();
    if (!s.masterEnabled) return;

    // Validate category
    const cat = SYNTH[category] ? category : EVENT_MAP[category];
    if (!cat || !SYNTH[cat]) return;

    // Play haptic
    if (s.hapticEnabled && !prefersReducedMotion()) {
      triggerHaptic(HAPTIC_PATTERN[cat] || [20]);
    }

    // Play sound regardless of quiet hours
    if (!prefersReducedMotion()) {
      const ctx = getCtx();
      if (ctx) {
        try {
          SYNTH[cat](ctx, s.volume);
        } catch (e) {
          console.warn('[HEYS.audio] Preview error:', cat, e);
        }
      }
    }

    console.info('[HEYS.audio] 🎵 preview:', category, '->', cat);
  }

  // ─── Public API ───────────────────────────────────────────────────────────
  HEYS.audio = {
    play,
    playCategory: play,
    haptic,
    preview,
    testCategory: preview,
    canPlay,
    stopAll: () => {
      if (_audioCtx?.close) {
        _audioCtx.close().catch(() => {});
        _audioCtx = null;
      }
      if (HEYS.vibration?.stop) {
        HEYS.vibration.stop();
      } else {
        navigator.vibrate?.(0);
      }
    },
    isEnabled: () => loadSettings().masterEnabled,
    getSettings: () => toPublicSettings(loadSettings()),
    saveSettings,
    setSettings: saveSettings,
    invalidateSettings,
    EVENTS: Object.freeze(Object.assign({}, EVENT_MAP)),
    CATEGORIES: Object.freeze(Object.keys(SYNTH))
  };

  console.info('[HEYS.audio] ✅ Unified audio module loaded (v1.0.0)');

})(typeof window !== 'undefined' ? window : global);


/* ===== heys_pwa_module_v1.js ===== */
/**
 * HEYS PWA Update Manager v1.0
 * =============================
 * Progressive Web App update management and version control
 * 
 * Features:
 * - Version tracking & semantic comparison
 * - Update badge notification (non-intrusive)
 * - Update modal with progress stages
 * - Network quality detection
 * - Smart periodic version checks
 * - Manual refresh prompts (iOS fallback)
 * - Update lock/unlock mechanisms
 * - Exponential backoff for failed checks
 * 
 * Scientific Foundation:
 * - Progressive Enhancement (Aaron Gustafson, 2008)
 * - User-Centric Performance Metrics (Google Web Vitals)
 * - Service Worker Lifecycle (W3C)
 * 
 * @version 1.0.0
 * @feature-flag modular_pwa
 */

(function () {
  'use strict';

  const HEYS = window.HEYS = window.HEYS || {};

  // Check feature flag - если используется legacy mode, пропускаем модуль
  if (HEYS.featureFlags?.isEnabled('use_legacy_monolith')) {
    if (HEYS.featureFlags?.isEnabled('dev_module_logging')) {
      console.log('[PWA] ⏭️ Skipped (legacy monolith mode)');
    }
    return;
  }

  // Performance tracking start
  HEYS.modulePerf?.startLoad('pwa_module');

  if (HEYS.featureFlags?.isEnabled('dev_module_logging')) {
    console.log('[PWA] 📦 Loading module...');
  }

  // ============================================================================
  // EXTRACTED CODE FROM heys_app_v12.js (lines 18-479)
  // ============================================================================

  // === App Version & Auto-logout on Update ===
  const APP_VERSION = '2026.03.16.1743.95b2f797'; // synced with build-meta.json on 2026-02-26

  HEYS.version = APP_VERSION;

  // 🔍 PWA Debug helper — показать boot лог (вызвать в консоли или после загрузки)
  HEYS.showBootLog = function () {
    try {
      const log = JSON.parse(localStorage.getItem('heys_boot_log') || '[]');
      console.table(log);
      return log;
    } catch (e) {
      console.log('No boot log');
      return [];
    }
  };

  // 🔍 PWA Debug — включить/выключить vConsole
  HEYS.enableDebug = function (enabled = true) {
    localStorage.setItem('heys_debug', enabled ? '1' : '0');
    console.log('Debug mode:', enabled ? 'ON (reload to see vConsole)' : 'OFF');
  };

  // === Семантическое сравнение версий ===
  // Версия: YYYY.MM.DD.HHMM.hash → сравниваем числовую часть
  const getUpdateHelpers = () => HEYS.PlatformAPIs || {};

  const isNewerVersion = (serverVersion, currentVersion) => {
    return HEYS.PlatformAPIs?.isNewerVersion?.(serverVersion, currentVersion) ?? false;
  };

  const isUpdateLocked = () => getUpdateHelpers().isUpdateLocked?.() ?? false;
  const setUpdateLock = () => getUpdateHelpers().setUpdateLock?.();
  const clearUpdateLock = () => getUpdateHelpers().clearUpdateLock?.();
  const showUpdateBadge = (version) => getUpdateHelpers().showUpdateBadge?.(version);
  const hideUpdateBadge = () => getUpdateHelpers().hideUpdateBadge?.();
  const showUpdateModal = (stage) => getUpdateHelpers().showUpdateModal?.(stage);
  const updateModalStage = (stage) => getUpdateHelpers().updateModalStage?.(stage);
  const hideUpdateModal = () => getUpdateHelpers().hideUpdateModal?.();
  const showManualRefreshPrompt = (version) => getUpdateHelpers().showManualRefreshPrompt?.(version);
  const checkServerVersion = (silent = true) => getUpdateHelpers().checkServerVersion?.(silent);
  const getNetworkQuality = () => getUpdateHelpers().getNetworkQuality?.() || { type: 'unknown', quality: 'good' };
  const smartVersionCheck = () => getUpdateHelpers().smartVersionCheck?.();

  HEYS.installUpdate = async () => {
    return getUpdateHelpers().installUpdate?.();
  };

  // ============================================================================
  // MODULE EXPORTS
  // ============================================================================

  // Экспортируем PWA API в namespace
  HEYS.PWA = {
    // Version
    version: APP_VERSION,
    isNewerVersion: isNewerVersion,

    // Update lock
    isUpdateLocked: isUpdateLocked,
    setUpdateLock: setUpdateLock,
    clearUpdateLock: clearUpdateLock,

    // Update badge
    showUpdateBadge: showUpdateBadge,
    hideUpdateBadge: hideUpdateBadge,
    installUpdate: HEYS.installUpdate,

    // Network quality
    getNetworkQuality: getNetworkQuality,

    // Smart checks
    smartVersionCheck: smartVersionCheck,
    checkServerVersion: checkServerVersion,

    // Update modal
    showUpdateModal: showUpdateModal,
    updateModalStage: updateModalStage,
    hideUpdateModal: hideUpdateModal,

    // Manual refresh
    showManualRefreshPrompt: showManualRefreshPrompt,

    // Expose globals for backward compatibility
    _updateAvailable: () => (HEYS.PlatformAPIs?.getUpdateState?.().available ?? false),
    _updateVersion: () => (HEYS.PlatformAPIs?.getUpdateState?.().version ?? null)
  };

  // Performance tracking end
  HEYS.modulePerf?.endLoad('pwa_module', true);

  if (HEYS.featureFlags?.isEnabled('dev_module_logging')) {
    console.log('[PWA] ✅ Module loaded successfully');
  }
})();


/* ===== heys_simple_analytics.js ===== */
/**
 * HEYS Simple Analytics v1.0
 * Минималистичная система мониторинга для приложения учета питания
 * 
 * Заменяет 11,500+ строк избыточного кода на ~100 строк функционального трекинга
 * 
 * Что отслеживается:
 * - Медленные поисковые запросы (>1s)
 * - Медленные API вызовы (>2s)
 * - Операции с данными (кеш, синхронизация)
 * - JavaScript ошибки
 * 
 * Что НЕ отслеживается (избыточно для nutrition app):
 * - FPS и рендеринг
 * - Детальная память
 * - Клики и скроллы
 * - Browser fingerprinting
 */

(function (global) {
  'use strict';

  const HEYS = global.HEYS = global.HEYS || {};

  // ==================== КОНСТАНТЫ ====================

  // Пороги для предупреждений о медленных операциях (в миллисекундах)
  const THRESHOLDS = {
    SLOW_SEARCH: 1000,      // 1 секунда
    SLOW_API: 2000,         // 2 секунды
    CRITICAL_API: 5000      // 5 секунд
  };

  // Конвертация единиц измерения
  const CONVERSION = {
    MS_TO_SECONDS: 1000     // миллисекунды → секунды
  };

  // Счетчики для статистики
  const stats = {
    searches: { total: 0, slow: 0 },
    apiCalls: { total: 0, slow: 0, failed: 0 },
    errors: { total: 0 },
    cacheHits: 0,
    cacheMisses: 0,
    sessionStart: Date.now()
  };

  const DEBUG_EVENTS_KEY = 'heys_debug_events';
  const DEBUG_EVENTS_LIMIT = 50;
  const debugEvents = [];

  const readStoredValue = (key, fallback = null) => {
    let value;
    if (HEYS.store?.get) {
      value = HEYS.store.get(key, fallback);
    } else if (HEYS.utils?.lsGet) {
      value = HEYS.utils.lsGet(key, fallback);
    } else {
      try {
        value = localStorage.getItem(key);
      } catch (e) {
        return fallback;
      }
    }

    if (value == null) return fallback;

    if (typeof value === 'string') {
      if (value.startsWith('¤Z¤') && HEYS.store?.decompress) {
        try {
          value = HEYS.store.decompress(value.slice(3));
        } catch (e) { }
      }
      try {
        return JSON.parse(value);
      } catch (e) {
        return value;
      }
    }

    return value;
  };

  const writeStoredValue = (key, value) => {
    if (HEYS.store?.set) {
      return HEYS.store.set(key, value);
    }
    if (HEYS.utils?.lsSet) {
      return HEYS.utils.lsSet(key, value);
    }
    localStorage.setItem(key, JSON.stringify(value));
  };

  function recordDebugEvent(type, payload) {
    try {
      const entry = {
        t: Date.now(),
        type: type || 'unknown',
        payload: payload || null
      };
      debugEvents.push(entry);
      if (debugEvents.length > DEBUG_EVENTS_LIMIT) {
        debugEvents.splice(0, debugEvents.length - DEBUG_EVENTS_LIMIT);
      }
      try {
        writeStoredValue(DEBUG_EVENTS_KEY, debugEvents);
      } catch (e) { }
    } catch (e) { }
  }

  // ==================== CORE ФУНКЦИИ ====================

  /**
   * Трекинг поисковых запросов
   * Логирует медленные поиски для оптимизации
   * 
   * @param {string} query - Поисковый запрос пользователя
   * @param {number} resultsCount - Количество найденных результатов
   * @param {number} duration - Время выполнения запроса в миллисекундах
   * 
   * @example
   * trackSearch('творог', 15, 450); // Быстрый поиск, не логируется
   * trackSearch('молоко', 120, 1500); // Медленный поиск, логируется предупреждение
   */
  function trackSearch(query, resultsCount, duration) {
    stats.searches.total++;

    if (duration > THRESHOLDS.SLOW_SEARCH) {
      stats.searches.slow++;
      DEV.warn('[HEYS Analytics] Медленный поиск:', {
        query: query,
        duration: `${duration.toFixed(0)}ms`,
        results: resultsCount,
        threshold: `${THRESHOLDS.SLOW_SEARCH}ms`
      });
    }
  }

  /**
   * Трекинг API вызовов (Supabase, парсинг и т.д.)
   * Помогает выявить проблемы с сетью или backend
   * 
   * @param {string} apiName - Название API метода (например, 'supabase.products.list')
   * @param {number} duration - Время выполнения запроса в миллисекундах
   * @param {boolean} [success=true] - Успешность выполнения запроса
   * 
   * @example
   * trackApiCall('supabase.signin', 800, true); // Быстрый успешный вызов
   * trackApiCall('fdc.search', 3000, true); // Медленный, но успешный
   * trackApiCall('fdc.search', 500, false); // Быстрая ошибка
   */
  function trackApiCall(apiName, duration, success = true) {
    stats.apiCalls.total++;

    if (!success) {
      stats.apiCalls.failed++;
      console.error('[HEYS Analytics] API ошибка:', {
        api: apiName,
        duration: `${duration.toFixed(0)}ms`
      });
      return;
    }

    if (duration > THRESHOLDS.CRITICAL_API) {
      stats.apiCalls.slow++;
      console.error('[HEYS Analytics] Критически медленный API:', {
        api: apiName,
        duration: `${duration.toFixed(0)}ms`,
        threshold: `${THRESHOLDS.CRITICAL_API}ms`
      });
    } else if (duration > THRESHOLDS.SLOW_API) {
      stats.apiCalls.slow++;
      DEV.warn('[HEYS Analytics] Медленный API:', {
        api: apiName,
        duration: `${duration.toFixed(0)}ms`,
        threshold: `${THRESHOLDS.SLOW_API}ms`
      });
    }
  }

  /**
   * Трекинг операций с данными
   * Помогает оценить эффективность кеширования
   * 
   * @param {string} operationType - Тип операции: 'cache-hit' | 'cache-miss'
  * @param {number} [count=1] - Количество операций (для batch операций)
  * @param {Object} [meta] - Доп. данные (только для debug-событий)
   * 
   * @example
   * trackDataOperation('cache-hit'); // Найдено в кеше
   * trackDataOperation('cache-miss'); // Загрузка из источника
   * trackDataOperation('cache-hit', 50); // Batch операция
   */
  function trackDataOperation(operationType, count = 1, meta) {
    switch (operationType) {
      case 'cache-hit':
        stats.cacheHits += count;
        break;
      case 'cache-miss':
        stats.cacheMisses += count;
        break;
      default:
        recordDebugEvent(operationType, {
          count: typeof count === 'number' ? count : 1,
          meta: meta || null
        });
        break;
    }
  }

  /**
   * Базовый error tracking
   * Перехватывает необработанные JavaScript ошибки
   * 
   * @param {Error|string} error - Объект ошибки или строка с описанием
   * @param {string} [source='unknown'] - Источник ошибки (модуль, функция)
   * 
   * @example
   * trackError(new Error('Failed to fetch'), 'ProductsManager.search');
   * trackError('Invalid JSON format', 'localStorage.parse');
   */
  function trackError(error, source = 'unknown') {
    stats.errors.total++;
    console.error('[HEYS Analytics] Ошибка:', {
      message: error.message || String(error),
      source: source,
      stack: error.stack || 'N/A'
    });
  }

  /**
   * Получить текущую статистику сессии
   * Возвращает агрегированные метрики по поиску, API, кешу и ошибкам
   * 
   * @returns {Object} Статистика сессии с метриками производительности
   * 
   * @example
   * const stats = getStats();
   * console.log(stats.searches.slowRate); // "15.5%"
   * console.log(stats.cache.hitRate); // "87.3%"
   */
  function getStats() {
    const sessionDuration = Date.now() - stats.sessionStart;
    const cacheTotal = stats.cacheHits + stats.cacheMisses;
    const cacheHitRate = cacheTotal > 0
      ? ((stats.cacheHits / cacheTotal) * 100).toFixed(1)
      : 0;

    return {
      session: {
        duration: `${(sessionDuration / CONVERSION.MS_TO_SECONDS).toFixed(0)}s`,
        start: new Date(stats.sessionStart).toISOString()
      },
      searches: {
        ...stats.searches,
        slowRate: stats.searches.total > 0
          ? `${((stats.searches.slow / stats.searches.total) * 100).toFixed(1)}%`
          : '0%'
      },
      apiCalls: {
        ...stats.apiCalls,
        slowRate: stats.apiCalls.total > 0
          ? `${((stats.apiCalls.slow / stats.apiCalls.total) * 100).toFixed(1)}%`
          : '0%',
        failRate: stats.apiCalls.total > 0
          ? `${((stats.apiCalls.failed / stats.apiCalls.total) * 100).toFixed(1)}%`
          : '0%'
      },
      cache: {
        hits: stats.cacheHits,
        misses: stats.cacheMisses,
        hitRate: `${cacheHitRate}%`
      },
      errors: stats.errors
    };
  }

  /**
   * Экспорт метрик для отладки в консоли браузера
   * Вызывается через heysStats() в DevTools
   * 
   * @returns {Object} Полная статистика сессии
   * 
   * @example
   * // В консоли браузера:
   * heysStats(); // Выведет полную статистику
   */
  function exportMetrics() {
    const metrics = getStats();
    DEV.log('[HEYS Analytics] Статистика сессии:', metrics);
    return metrics;
  }

  // Глобальный обработчик ошибок
  global.addEventListener('error', function (event) {
    trackError(event.error || new Error(event.message), 'window.onerror');
  });

  // Обработчик promise rejections
  global.addEventListener('unhandledrejection', function (event) {
    trackError(new Error(event.reason), 'unhandledRejection');
  });

  // Экспорт в HEYS namespace
  HEYS.analytics = {
    trackSearch,
    trackApiCall,
    trackDataOperation,
    trackError,
    getStats,
    exportMetrics,

    // Aliases для совместимости с legacy кодом
    trackModuleLoad: () => { }, // no-op
    trackComponentRender: () => { }, // no-op
    trackUserInteraction: () => { }, // no-op
    startTracking: () => { },
    stopTracking: () => { },
    reset: () => {
      stats.searches = { total: 0, slow: 0 };
      stats.apiCalls = { total: 0, slow: 0, failed: 0 };
      stats.errors = { total: 0 };
      stats.cacheHits = 0;
      stats.cacheMisses = 0;
      stats.sessionStart = Date.now();
    },
    getMetrics: getStats,
    trackEvent: () => { } // no-op alias
  };

  // Alias для совместимости с heys_reports_v12.js
  HEYS.performance = {
    // Методы из analytics
    ...HEYS.analytics,

    // Дополнительные методы для reports
    increment: (metric) => {
      // Используем trackDataOperation для совместимости
      trackDataOperation(metric, 1);
    },

    measure: (name, fn) => {
      // Простой wrapper без реального измерения времени
      // (для reports время не критично)
      return fn();
    }
  };

  // Лог инициализации отключен для чистой консоли

  // Debug: экспорт статистики в глобальный scope для отладки
  global.heysStats = getStats;

})(window);


