    rpc,
    rest,
    sendSMS,
    saveLead,
    healthCheck,

    // Auth методы
    getClientSalt,
    verifyClientPin,
    curatorLogin,
    verifyCuratorToken,

    // 👥 Clients
    getClients,
    createClient,
    updateClient,
    deleteClient,

