          sodium100: product.sodium100 ?? null,
          omega3_100: product.omega3_100 ?? null,
          omega6_100: product.omega6_100 ?? null,
          nova_group: product.nova_group ?? product.novaGroup ?? null,
          additives: product.additives ?? null,
