  function normalizeProductName(name) {
    if (!name) return '';
    return name
      .toLowerCase()
      .trim()
      .replace(/\s+/g, ' ')
      .replace(/ё/g, 'е'); // Русская нормализация
  }

  M.computeProductFingerprint = computeProductFingerprint;
